{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "version": "arkpilot-a2ui/v2",
  "dataModel": {
    "entities": {
      "Dish": {
        "fields": ["id", "name", "ingredients", "cuisine", "cookingMethod", "difficulty", "moodTags", "mealTimes", "calories"],
        "source": "preset local DishLibrary (used for ingredient matching and filtering)",
        "persistence": "read-only preset"
      },
      "Ingredient": {
        "fields": ["id", "name", "quantity", "expireDate"],
        "source": "user input on ingredients-page",
        "persistence": "Preferences (durable)"
      },
      "WheelCandidate": {
        "fields": ["id", "name"],
        "source": "user edit on wheel-editor-sheet",
        "persistence": "Preferences (durable); default empty"
      },
      "CheckIn": {
        "fields": ["id", "date", "slot", "dish", "tag", "mood", "photoUri"],
        "source": "user input on checkin-form-sheet",
        "persistence": "Preferences (durable)"
      },
      "FilterSelections": {
        "fields": ["mood", "time", "cuisine", "cookingMethod"],
        "source": "filters-page inputs",
        "persistence": "session only (reset on leave)"
      },
      "ShareCardData": {
        "fields": ["date", "dish", "caption", "tag", "template"],
        "source": "derived from latest checkin or wheel result",
        "persistence": "session only"
      }
    },
    "enums": ["Mood", "MealTime", "Cuisine", "CookingMethod", "MealSlot", "CheckInTag", "WheelState", "ShareTemplate"],
    "settingsFormState": ["user.name (default 美食家)", "wheelCandidates (default empty)", "app.version"],
    "computedState": [
      "/checkin/streak (consecutive days with >=1 checkin ending today or yesterday)",
      "/checkin/monthly-count (current month checkin count)",
      "/checkin/today-summary (completed meals today / 4)",
      "/user/greeting (time-of-day greeting)",
      "/date/today (formatted today)",
      "/ingredients/recommendations (match score + difficulty sort)",
      "/filters/results + /filters/result-count",
      "/wheel/result (final candidate after stop)"
    ],
    "persistenceRelevantFields": ["ingredients", "checkins", "wheelCandidates", "userName"]
  },
  "services": {
    "StorageService": {
      "boundary": "Preferences wrapper over @kit.ArkData; JSON-serialized lists",
      "responsibilities": ["load/save ingredients", "load/save checkins", "load/save wheelCandidates", "load/save userName", "clearAll"],
      "storeName": "eat-what-store"
    },
    "DishRecommendService": {
      "boundary": "pure local recommendation + filtering engine over DishLibrary",
      "responsibilities": ["recommendByIngredients(ingredients)", "filterBySelections(mood,time,cuisine,cookingMethod)", "matchScore(dish, ingredients)"]
    },
    "CheckInService": {
      "boundary": "checkin aggregation and streak computation",
      "responsibilities": ["addCheckin", "todayMeals(checkins, date)", "streak(checkins)", "monthlyCount(checkins)", "history(checkins, limit)", "summary(checkins, date)"]
    },
    "WheelService": {
      "boundary": "wheel spin result computation",
      "responsibilities": ["pickRandom(candidates)", "nextRotation(durationMs)"],
      "note": "actual animation timing is UI-owned; service only computes the chosen candidate and rotation target"
    },
    "ShareService": {
      "boundary": "share card data assembly and system share/save dispatch",
      "responsibilities": ["buildCardData(source, caption, template)", "templates list", "saveToAlbum stub", "shareCard stub"],
      "fallback": "save/share require Canvas render + system share API; rendered in visual phase, current logic exposes data + dispatch hooks"
    }
  },
  "stateMachine": {
    "WheelState": {
      "Idle": ["wheel-start -> Spinning"],
      "Spinning": ["wheel-stop -> Stopped", "wheel-spin-again -> Spinning"],
      "Stopped": ["wheel-spin-again -> Spinning", "open-wheel-editor -> Idle"]
    },
    "WheelEditorState": ["closed -> open-wheel-editor -> open", "open -> close-wheel-editor|save-wheel-candidate|delete-wheel-candidate -> closed"],
    "CheckInFormState": ["closed -> checkin-{slot} -> open", "open -> save-checkin|cancel-checkin -> closed"],
    "FiltersState": {
      "Unapplied": ["select-* -> Unapplied", "apply-filters -> Applied", "reset-filters -> Unapplied"],
      "Applied": ["select-* -> Unapplied", "apply-filters -> Applied", "reset-filters -> Unapplied"]
    }
  },
  "interactionFlows": [
    {
      "flow": "wheel-spin",
      "trigger": "wheel-start-button",
      "steps": [
        "guard candidates.length >= 2 else show wheel-empty-candidates",
        "set /wheel/state = spinning, disable start",
        "WheelService computes random candidate + rotation target",
        "on wheel-stop-button or auto-deceleration -> set /wheel/result, /wheel/state = stopped",
        "enable wheel-again-button + wheel-checkin-button"
      ],
      "errorPaths": ["candidates < 2 -> wheel-empty-candidates assertion", "empty result fallback -> first candidate"]
    },
    {
      "flow": "wheel-candidate-edit",
      "trigger": "wheel-edit-button / wheel-add-candidate-button",
      "steps": ["open wheel-editor-sheet", "input wheel-editor-input", "save-wheel-candidate persists via StorageService", "delete-wheel-candidate removes by id"],
      "sideEffects": ["wheel-candidate-list reflects updated persisted candidates"]
    },
    {
      "flow": "ingredient-recommend",
      "trigger": "ingredients-add-button -> ingredients-recommend-button",
      "steps": ["ingredient-name-change -> add-ingredient persists", "get-recommendations -> DishRecommendService.recommendByIngredients", "render ingredients-recommend-list or ingredients-no-recommendations"],
      "errorPaths": ["empty ingredients -> recommend disabled", "no matches -> ingredients-no-recommendations"]
    },
    {
      "flow": "filters-apply",
      "trigger": "filters-apply-button",
      "steps": ["collect filters-mood/time/cuisine/cookingMethod", "DishRecommendService.filterBySelections", "render filters-result-list + filters-result-count"],
      "errorPaths": ["no filter set -> full list", "no results -> filters-no-results"]
    },
    {
      "flow": "checkin-meal",
      "trigger": "checkin-{breakfast|lunch|dinner|snack}-button",
      "steps": ["open checkin-form-sheet with active slot", "checkin-dish-change + checkin-mood-change + checkin-tag-change", "save-checkin persists CheckIn, refresh /checkin/streak, monthly-count, today-summary"],
      "sideEffects": ["checkin-history-list + checkin-meal-list update"]
    },
    {
      "flow": "share-card",
      "trigger": "checkin-share-button / wheel-checkin-button -> navigate-to-share",
      "steps": ["ShareService.buildCardData from latest checkin or wheel result", "select-card-template / share-caption-change update preview", "save-card-to-album | share-card dispatch (visual phase Canvas + system share)"]
    },
    {
      "flow": "home-entry",
      "steps": ["load persisted state", "compute /user/greeting + /date/today", "render today-summary + streak"]
    },
    {
      "flow": "profile-data-management",
      "trigger": "profile-clear-data-button",
      "steps": ["confirm dialog", "StorageService.clearAll", "reset in-memory controllers"]
    }
  ],
  "testTargets": {
    "assertions": ["home-greeting", "home-date-label", "home-streak-count", "home-checkin-summary", "wheel-result-label", "wheel-canvas", "filters-result-count", "checkin-streak-count", "checkin-monthly-count", "share-card-preview"],
    "actions": ["home-wheel-card", "home-ingredients-card", "home-filters-card", "home-checkin-button", "wheel-start-button", "wheel-stop-button", "wheel-edit-button", "wheel-again-button", "ingredients-add-button", "ingredients-recommend-button", "filters-apply-button", "filters-reset-button", "checkin-breakfast-button", "checkin-lunch-button", "checkin-dinner-button", "checkin-snack-button", "share-save-button", "share-send-button"],
    "inputs": ["ingredients-input", "wheel-editor-input", "checkin-form-dish-input", "share-caption-input"],
    "lists": ["wheel-candidate-list", "ingredients-list", "ingredients-recommend-list", "filters-result-list", "checkin-meal-list", "checkin-history-list"]
  },
  "changeRequests": []
}

