input.content:
// Core domain models for 今天吃什么.
// Explicitly typed classes so they serialize/deserialize cleanly via
// StorageService (Preferences) and stay static-check friendly.

import {
  CheckInTag,
  CookingMethod,
  Cuisine,
  MealSlot,
  MealTime,
  Mood,
  ShareTemplate,
} from '../common/Enums';

export enum Difficulty {
  Easy = 'easy',
  Medium = 'medium',
  Hard = 'hard',
}

export const DIFFICULTY_LABELS: Record<string, string> = {
  [Difficulty.Easy]: '简单',
  [Difficulty.Medium]: '中等',
  [Difficulty.Hard]: '较难',
};

// Preset dish used by recommendation + filtering. Read-only.
export class Dish {
  id: string = '';
  name: string = '';
  ingredients: string[] = [];
  cuisine: Cuisine = Cuisine.Chinese;
  cookingMethod: CookingMethod = CookingMethod.Quick;
  difficulty: Difficulty = Difficulty.Easy;
  moodTags: Mood[] = [];
  mealTimes: MealTime[] = [];
  calories: number = 0;

  constructor(o?: DishShape) {
    if (o) {
      this.id = o.id;
      this.name = o.name;
      this.ingredients = o.ingredients;
      this.cuisine = o.cuisine;
      this.cookingMethod = o.cookingMethod;
      this.difficulty = o.difficulty;
      this.moodTags = o.moodTags;
      this.mealTimes = o.mealTimes;
      this.calories = o.calories;
    }
  }
}

export interface DishShape {
  id: string;
  name: string;
  ingredients: string[];
  cuisine: Cuisine;
  cookingMethod: CookingMethod;
  difficulty: Difficulty;
  moodTags: Mood[];
  mealTimes: MealTime[];
  calories: number;
}

// User-managed fridge ingredient. Persisted.
export class Ingredient {
  id: string = '';
  name: string = '';
  quantity: string = '';
  expireDate: string = '';

  constructor(o?: IngredientShape) {
    if (o) {
      this.id = o.id;
      this.name = o.name;
      this.quantity = o.quantity;
      this.expireDate = o.expireDate;
    }
  }

  toObject(): IngredientShape {
    return {
      id: this.id,
      name: this.name,
      quantity: this.quantity,
      expireDate: this.expireDate,
    };
  }

  static fromObject(o: IngredientShape): Ingredient {
    return new Ingredient(o);
  }
}

export interface IngredientShape {
  id: string;
  name: string;
  quantity: string;
  expireDate: string;
}

// Wheel candidate. Persisted (default empty per spec open question).
export class WheelCandidate {
  id: string = '';
  name: string = '';

  constructor(o?: WheelCandidateShape) {
    if (o) {
      this.id = o.id;
      this.name = o.name;
    }
  }

  toObject(): WheelCandidateShape {
    return { id: this.id, name: this.name };
  }

  static fromObject(o: WheelCandidateShape): WheelCandidate {
    return new WheelCandidate(o);
  }
}

export interface WheelCandidateShape {
  id: string;
  name: string;
}

// Daily check-in record. Persisted.
export class CheckIn {
  id: string = '';
  date: string = ''; // YYYY-MM-DD
  slot: MealSlot = MealSlot.Breakfast;
  dish: string = '';
  tag: CheckInTag = CheckInTag.HomeCooked;
  mood: Mood = Mood.Treat;
  photoUri: string = '';

  constructor(o?: CheckInShape) {
    if (o) {
      this.id = o.id;
      this.date = o.date;
      this.slot = o.slot;
      this.dish = o.dish;
      this.tag = o.tag;
      this.mood = o.mood;
      this.photoUri = o.photoUri;
    }
  }

  toObject(): CheckInShape {
    return {
      id: this.id,
      date: this.date,
      slot: this.slot,
      dish: this.dish,
      tag: this.tag,
      mood: this.mood,
      photoUri: this.photoUri,
    };
  }

  static fromObject(o: CheckInShape): CheckIn {
    return new CheckIn(o);
  }
}

export interface CheckInShape {
  id: string;
  date: string;
  slot: MealSlot;
  dish: string;
  tag: CheckInTag;
  mood: Mood;
  photoUri: string;
}

// Today meal status row for checkin-meal-list (itemIdPattern checkin-meal-{slot}).
export class MealStatus {
  slot: MealSlot = MealSlot.Breakfast;
  label: string = '';
  completed: boolean = false;
  dish: string = '';

  constructor(slot: MealSlot, label: string, completed: boolean, dish: string) {
    this.slot = slot;
    this.label = label;
    this.completed = completed;
    this.dish = dish;
  }
}

// Filter selections on filters-page (session only).
export class FilterSelections {
  mood: Mood | string = '';
  time: MealTime | string = '';
  cuisine: Cuisine | string = '';
  cookingMethod: CookingMethod | string = '';

  isEmpty(): boolean {
    return this.mood === '' && this.time === '' && this.cuisine === '' && this.cookingMethod === '';
  }

  clone(): FilterSelections {
    const c: FilterSelections = new FilterSelections();
    c.mood = this.mood;
    c.time = this.time;
    c.cuisine = this.cuisine;
    c.cookingMethod = this.cookingMethod;
    return c;
  }
}

// Recommendation row (binding /ingredients/recommendations).
export class Recommendation {
  dish: Dish;
  match: number; // 0..1 matched ingredient ratio

  constructor(dish: Dish, match: number) {
    this.dish = dish;
    this.match = match;
  }
}

// Filter result row (binding /filters/results).
export class FilterResult {
  dish: Dish;
  tags: string[];

  constructor(dish: Dish, tags: string[]) {
    this.dish = dish;
    this.tags = tags;
  }
}

// Share card payload (binding /share/card-data).
export class ShareCardData {
  date: string = '';
  dish: string = '';
  caption: string = '';
  tag: string = '';
  template: ShareTemplate = ShareTemplate.Warm;

  constructor(o?: ShareCardDataShape) {
    if (o) {
      this.date = o.date;
      this.dish = o.dish;
      this.caption = o.caption;
      this.tag = o.tag;
      this.template = o.template;
    }
  }
}

export interface ShareCardDataShape {
  date: string;
  dish: string;
  caption: string;
  tag: string;
  template: ShareTemplate;
}

