// Pure date helpers shared by CheckInService, HomeController, etc.
// No HarmonyOS SDK dependency so it stays trivially static-checkable.

export class DateUtil {
  // YYYY-MM-DD in local time.
  static toDateKey(d: Date): string {
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    const mm: string = m < 10 ? `0${m}` : `${m}`;
    const dd: string = day < 10 ? `0${day}` : `${day}`;
    return `${y}-${mm}-${dd}`;
  }

  static todayKey(now: Date = new Date()): string {
    return DateUtil.toDateKey(now);
  }

  static addDays(d: Date, delta: number): Date {
    const copy: Date = new Date(d.getTime());
    copy.setDate(copy.getDate() + delta);
    return copy;
  }

  static sameMonthYear(a: Date, b: Date): boolean {
    return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth();
  }

  // 6月20日 星期五
  static prettyLabel(d: Date = new Date()): string {
    const month: number = d.getMonth() + 1;
    const day: number = d.getDate();
    const names: string[] = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
    return `${month}月${day}日 ${names[d.getDay()]}`;
  }

  // Time-of-day greeting.
  static greeting(now: Date = new Date()): string {
    const h: number = now.getHours();
    if (h < 6) {
      return '夜深了，吃点暖的吧？';
    } else if (h < 11) {
      return '早上好，今天想吃点什么？';
    } else if (h < 14) {
      return '中午好，来决定午餐吧！';
    } else if (h < 18) {
      return '下午好，来杯下午茶？';
    } else if (h < 22) {
      return '晚上好，今天想吃点什么？';
    }
    return '夜宵时间到啦，吃点什么？';
  }

  // Consecutive days with >=1 checkin. Today may be empty without breaking the
  // streak (streak measured ending today-or-yesterday).
  static streakDays(dateSet: Set<string>, now: Date = new Date()): number {
    let cursor: Date = now;
    if (!dateSet.has(DateUtil.toDateKey(cursor))) {
      cursor = DateUtil.addDays(cursor, -1);
      if (!dateSet.has(DateUtil.toDateKey(cursor))) {
        return 0;
      }
    }
    let count: number = 0;
    while (dateSet.has(DateUtil.toDateKey(cursor))) {
      count++;
      cursor = DateUtil.addDays(cursor, -1);
    }
    return count;
  }
}

