// Local persistence boundary over HarmonyOS Preferences (@kit.ArkData).
// All durable user data (ingredients, checkins, wheel candidates, user name)
// is JSON-serialized into a single store. Controllers call loadAll()/save*().
import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { CheckIn, CheckInShape, Ingredient, IngredientShape, WheelCandidate, WheelCandidateShape } from '../model/Models';

const STORE_NAME: string = 'eat-what-store';
const KEY_INGREDIENTS: string = 'ingredients';
const KEY_CHECKINS: string = 'checkins';
const KEY_WHEEL_CANDIDATES: string = 'wheel-candidates';
const KEY_USER_NAME: string = 'user-name';
const DEFAULT_USER_NAME: string = '美食家';

export interface StoreSnapshot {
  ingredients: Ingredient[];
  checkins: CheckIn[];
  wheelCandidates: WheelCandidate[];
  userName: string;
}

export class StorageService {
  private context: common.Context;

  constructor(context: common.Context) {
    this.context = context;
  }

  private async getStore(): Promise<preferences.Preferences> {
    return await preferences.getPreferences(this.context, STORE_NAME);
  }

  private async readString(key: string, fallback: string): Promise<string> {
    const store: preferences.Preferences = await this.getStore();
    const raw: preferences.ValueType = await store.get(key, fallback);
    return typeof raw === 'string' ? raw : fallback;
  }

  private async writeString(key: string, value: string): Promise<void> {
    const store: preferences.Preferences = await this.getStore();
    await store.put(key, value);
    await store.flush();
  }

  async loadAll(): Promise<StoreSnapshot> {
    const ingredientText: string = await this.readString(KEY_INGREDIENTS, '[]');
    const checkinText: string = await this.readString(KEY_CHECKINS, '[]');
    const candidateText: string = await this.readString(KEY_WHEEL_CANDIDATES, '[]');
    const userName: string = await this.readString(KEY_USER_NAME, DEFAULT_USER_NAME);

    return {
      ingredients: StorageService.parseIngredients(ingredientText),
      checkins: StorageService.parseCheckins(checkinText),
      wheelCandidates: StorageService.parseCandidates(candidateText),
      userName: userName && userName.length > 0 ? userName : DEFAULT_USER_NAME,
    };
  }

  async saveIngredients(items: Ingredient[]): Promise<void> {
    const shapes: IngredientShape[] = items.map((i: Ingredient) => i.toObject());
    await this.writeString(KEY_INGREDIENTS, JSON.stringify(shapes));
  }

  async saveCheckins(items: CheckIn[]): Promise<void> {
    const shapes: CheckInShape[] = items.map((c: CheckIn) => c.toObject());
    await this.writeString(KEY_CHECKINS, JSON.stringify(shapes));
  }

  async saveWheelCandidates(items: WheelCandidate[]): Promise<void> {
    const shapes: WheelCandidateShape[] = items.map((c: WheelCandidate) => c.toObject());
    await this.writeString(KEY_WHEEL_CANDIDATES, JSON.stringify(shapes));
  }

  async saveUserName(name: string): Promise<void> {
    await this.writeString(KEY_USER_NAME, name && name.length > 0 ? name : DEFAULT_USER_NAME);
  }

  async clearAll(): Promise<void> {
    await this.writeString(KEY_INGREDIENTS, '[]');
    await this.writeString(KEY_CHECKINS, '[]');
    await this.writeString(KEY_WHEEL_CANDIDATES, '[]');
    await this.writeString(KEY_USER_NAME, DEFAULT_USER_NAME);
  }

  private static parseIngredients(text: string): Ingredient[] {
    const arr: IngredientShape[] = JSON.parse(text) as IngredientShape[];
    return arr.map((s: IngredientShape) => Ingredient.fromObject(s));
  }

  private static parseCheckins(text: string): CheckIn[] {
    const arr: CheckInShape[] = JSON.parse(text) as CheckInShape[];
    return arr.map((s: CheckInShape) => CheckIn.fromObject(s));
  }

  private static parseCandidates(text: string): WheelCandidate[] {
    const arr: WheelCandidateShape[] = JSON.parse(text) as WheelCandidateShape[];
    return arr.map((s: WheelCandidateShape) => WheelCandidate.fromObject(s));
  }
}

