// Pure local recommendation + filtering engine over the preset DishLibrary.
// No SDK dependency, no persistence — callers feed inputs and read results.
import { CookingMethod, Cuisine, CUISINE_LABELS, DIFFICULTY_LABELS_PREFIX, MealTime, MEAL_TIME_LABELS, Mood, MOOD_LABELS } from '../common/Enums';
import { Dish } from '../model/Models';
import { DishLibrary } from '../data/DishLibrary';
import { FilterResult, FilterSelections, Ingredient, Recommendation } from '../model/Models';
import { Difficulty, DIFFICULTY_LABELS } from '../model/Models';

export class DishRecommendService {
  // Rank dishes by how many of the user's ingredients they use.
  // match = matchedIngredients / dishIngredients (0..1). Filtered to match > 0,
  // sorted by match desc then difficulty asc.
  static recommendByIngredients(ingredients: Ingredient[]): Recommendation[] {
    const owned: Set<string> = new Set<string>(
      ingredients.map((i: Ingredient) => i.name.trim()).filter((n: string) => n.length > 0)
    );
    if (owned.size === 0) {
      return [];
    }
    const scored: Recommendation[] = [];
    for (const dish of DishLibrary.all()) {
      let matched: number = 0;
      for (const ing of dish.ingredients) {
        if (owned.has(ing)) {
          matched++;
        }
      }
      if (matched === 0) {
        continue;
      }
      const ratio: number = dish.ingredients.length === 0 ? 0 : matched / dish.ingredients.length;
      scored.push(new Recommendation(dish, ratio));
    }
    scored.sort((a: Recommendation, b: Recommendation) => {
      if (b.match !== a.match) {
        return b.match - a.match;
      }
      return DishRecommendService.difficultyRank(a.dish) - DishRecommendService.difficultyRank(b.dish);
    });
    return scored;
  }

  static filterBySelections(sel: FilterSelections): FilterResult[] {
    const results: FilterResult[] = [];
    for (const dish of DishLibrary.all()) {
      if (!DishRecommendService.matches(dish, sel)) {
        continue;
      }
      results.push(new FilterResult(dish, DishRecommendService.tagsFor(dish)));
    }
    return results;
  }

  static matches(dish: Dish, sel: FilterSelections): boolean {
    if (sel.mood !== '' && !dish.moodTags.includes(sel.mood as Mood)) {
      return false;
    }
    if (sel.time !== '' && !dish.mealTimes.includes(sel.time as MealTime)) {
      return false;
    }
    if (sel.cuisine !== '' && dish.cuisine !== (sel.cuisine as Cuisine)) {
      return false;
    }
    if (sel.cookingMethod !== '' && dish.cookingMethod !== (sel.cookingMethod as CookingMethod)) {
      return false;
    }
    return true;
  }

  static tagsFor(dish: Dish): string[] {
    const tags: string[] = [];
    tags.push(CUISINE_LABELS[dish.cuisine] ?? dish.cuisine);
    tags.push(DIFFICULTY_LABELS[dish.difficulty] ?? dish.difficulty);
    for (const m of dish.moodTags) {
      tags.push(MOOD_LABELS[m] ?? m);
    }
    return tags;
  }

  private static difficultyRank(dish: Dish): number {
    if (dish.difficulty === Difficulty.Easy) {
      return 0;
    } else if (dish.difficulty === Difficulty.Medium) {
      return 1;
    }
    return 2;
  }
}

