// Checkin aggregation and streak computation. Pure logic over CheckIn[].
import { CHECK_IN_TAG_LABELS, CheckInTag, MEAL_SLOT_LABELS, MealSlot } from '../common/Enums';
import { CheckIn, MealStatus } from '../model/Models';
import { DateUtil } from '../util/DateUtil';

export interface CheckInSummary {
  completed: number;
  total: number;
}

export class CheckInService {
  static readonly SLOTS: MealSlot[] = [MealSlot.Breakfast, MealSlot.Lunch, MealSlot.Dinner, MealSlot.Snack];

  // Meal status rows for checkin-meal-list (binding /checkin/today-meals).
  static todayMeals(checkins: CheckIn[], dateKey: string = DateUtil.todayKey()): MealStatus[] {
    const today: CheckIn[] = checkins.filter((c: CheckIn) => c.date === dateKey);
    return CheckInService.SLOTS.map((slot: MealSlot) => {
      const hit: CheckIn | undefined = today.find((c: CheckIn) => c.slot === slot);
      return new MealStatus(slot, MEAL_SLOT_LABELS[slot] ?? slot, hit !== undefined, hit ? hit.dish : '');
    });
  }

  static summary(checkins: CheckIn[], dateKey: string = DateUtil.todayKey()): CheckInSummary {
    const slotsDone: Set<MealSlot> = new Set<MealSlot>();
    for (const c of checkins) {
      if (c.date === dateKey) {
        slotsDone.add(c.slot);
      }
    }
    return { completed: slotsDone.size, total: CheckInService.SLOTS.length };
  }

  static streak(checkins: CheckIn[]): number {
    const dateSet: Set<string> = new Set<string>(checkins.map((c: CheckIn) => c.date));
    return DateUtil.streakDays(dateSet);
  }

  static monthlyCount(checkins: CheckIn[], now: Date = new Date()): number {
    let count: number = 0;
    for (const c of checkins) {
      const parts: string[] = c.date.split('-');
      if (parts.length !== 3) {
        continue;
      }
      const d: Date = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
      if (DateUtil.sameMonthYear(d, now)) {
        count++;
      }
    }
    return count;
  }

  // Most recent first, capped.
  static history(checkins: CheckIn[], limit: number = 30): CheckIn[] {
    const sorted: CheckIn[] = checkins.slice().sort((a: CheckIn, b: CheckIn) => {
      if (b.date !== a.date) {
        return b.date < a.date ? -1 : 1;
      }
      return CheckInService.slotRank(b.slot) - CheckInService.slotRank(a.slot);
    });
    return sorted.slice(0, limit);
  }

  // Latest checkin overall (for share card source).
  static latest(checkins: CheckIn[]): CheckIn | null {
    if (checkins.length === 0) {
      return null;
    }
    return CheckInService.history(checkins, 1)[0];
  }

  static tagLabel(tag: CheckInTag): string {
    return CHECK_IN_TAG_LABELS[tag] ?? tag;
  }

  private static slotRank(slot: MealSlot): number {
    if (slot === MealSlot.Breakfast) {
      return 0;
    } else if (slot === MealSlot.Lunch) {
      return 1;
    } else if (slot === MealSlot.Dinner) {
      return 2;
    }
    return 3;
  }
}

