// Central observable view-model + state machine for 今天吃什么.
// Single source of truth over StorageService so feature slices stay consistent.
// Event methods are grouped by feature and map 1:1 onto ui-behavior.json flows.
import { CheckInTag, Mood, MealSlot, SHARE_TEMPLATE_LABELS, ShareTemplate, WheelState } from '../common/Enums';
import { CheckIn, FilterSelections, Ingredient, MealStatus, Recommendation, WheelCandidate } from '../model/Models';
import { FilterResult } from '../model/Models';
import { CheckInService, CheckInSummary } from '../service/CheckInService';
import { DishRecommendService } from '../service/DishRecommendService';
import { ShareService, ShareSource } from '../service/ShareService';
import { SpinPlan, WheelService } from '../service/WheelService';
import { StorageService } from '../service/StorageService';
import { DateUtil } from '../util/DateUtil';
import { ShareCardData } from '../model/Models';

const SPIN_DURATION_MS: number = 3200;

@Observed
export class AppStore {
  private storage: StorageService;
  private idCounter: number = 0;

  // ---- persisted state ----
  ingredients: Ingredient[] = [];
  checkins: CheckIn[] = [];
  wheelCandidates: WheelCandidate[] = [];
  userName: string = '美食家';

  // ---- wheel ----
  wheelState: WheelState = WheelState.Idle;
  wheelResult: string = '';
  wheelRotation: number = 0;
  private spinPlan: SpinPlan | null = null;
  editorOpen: boolean = false;
  editorDraft: string = '';
  editorEditingId: string = '';

  // ---- ingredients ----
  ingredientInput: string = '';
  recommendations: Recommendation[] = [];

  // ---- filters ----
  filterSelections: FilterSelections = new FilterSelections();
  filterResults: FilterResult[] = [];

  // ---- checkin form ----
  checkinFormOpen: boolean = false;
  checkinActiveMeal: MealSlot = MealSlot.Breakfast;
  checkinDish: string = '';
  checkinMood: Mood = Mood.Treat;
  checkinTag: CheckInTag = CheckInTag.HomeCooked;

  // ---- share ----
  shareSource: ShareSource | null = null;
  shareCard: ShareCardData | null = null;
  shareCaption: string = '';
  shareTemplate: ShareTemplate = ShareTemplate.Warm;

  constructor(storage: StorageService) {
    this.storage = storage;
  }

  static async create(context: object): Promise<AppStore> {
    const storage: StorageService = new StorageService(context as common.Context);
    const store: AppStore = new AppStore(storage);
    await store.reload();
    return store;
  }

  async reload(): Promise<void> {
    const snap = await this.storage.loadAll();
    this.ingredients = snap.ingredients;
    this.checkins = snap.checkins;
    this.wheelCandidates = snap.wheelCandidates;
    this.userName = snap.userName;
  }

  private nextId(prefix: string): string {
    this.idCounter += 1;
    return `${prefix}-${Date.now()}-${this.idCounter}`;
  }

  // ================= Home =================
  greeting(): string {
    return DateUtil.greeting();
  }

  todayLabel(): string {
    return DateUtil.prettyLabel();
  }

  streak(): number {
    return CheckInService.streak(this.checkins);
  }

  todaySummary(): CheckInSummary {
    return CheckInService.summary(this.checkins);
  }

  // ================= Wheel =================
  canSpinWheel(): boolean {
    return WheelService.canSpin(this.wheelCandidates);
  }

  startSpin(): boolean {
    if (this.wheelState === WheelState.Spinning) {
      return false;
    }
    const plan: SpinPlan | null = WheelService.planSpin(this.wheelCandidates, this.wheelRotation);
    if (plan === null) {
      return false;
    }
    this.spinPlan = plan;
    this.wheelState = WheelState.Spinning;
    this.wheelResult = '';
    const store: AppStore = this;
    setTimeout(() => {
      store.completeSpin();
    }, SPIN_DURATION_MS);
    return true;
  }

  // Manual stop from wheel-stop-button; resolves immediately.
  stopSpin(): void {
    if (this.wheelState !== WheelState.Spinning) {
      return;
    }
    this.completeSpin();
  }

  private completeSpin(): void {
    if (this.spinPlan === null) {
      this.wheelState = WheelState.Idle;
      return;
    }
    this.wheelRotation = this.spinPlan.targetRotation;
    this.wheelResult = this.spinPlan.winner.name;
    this.wheelState = WheelState.Stopped;
  }

  spinAgain(): void {
    this.startSpin();
  }

  openWheelEditor(editingId: string = ''): void {
    this.editorEditingId = editingId;
    const existing: WheelCandidate | undefined =
      editingId === '' ? undefined : this.wheelCandidates.find((c: WheelCandidate) => c.id === editingId);
    this.editorDraft = existing ? existing.name : '';
    this.editorOpen = true;
  }

  closeWheelEditor(): void {
    this.editorOpen = false;
    this.editorDraft = '';
    this.editorEditingId = '';
  }

  async saveWheelCandidate(): Promise<void> {
    const name: string = this.editorDraft.trim();
    if (name.length === 0) {
      this.closeWheelEditor();
      return;
    }
    if (this.editorEditingId !== '') {
      const next: WheelCandidate[] = this.wheelCandidates.map((c: WheelCandidate) =>
        c.id === this.editorEditingId ? new WheelCandidate({ id: c.id, name }) : c
      );
      this.wheelCandidates = next;
    } else {
      const candidate: WheelCandidate = new WheelCandidate({ id: this.nextId('candidate'), name });
      this.wheelCandidates = [...this.wheelCandidates, candidate];
    }
    await this.storage.saveWheelCandidates(this.wheelCandidates);
    this.closeWheelEditor();
  }

  async deleteWheelCandidate(id: string): Promise<void> {
    this.wheelCandidates = this.wheelCandidates.filter((c: WheelCandidate) => c.id !== id);
    await this.storage.saveWheelCandidates(this.wheelCandidates);
  }

  // ================= Ingredients =================
  async addIngredient(): Promise<void> {
    const name: string = this.ingredientInput.trim();
    if (name.length === 0) {
      return;
    }
    const ingredient: Ingredient = new Ingredient({ id: this.nextId('ing'), name, quantity: '', expireDate: '' });
    this.ingredients = [...this.ingredients, ingredient];
    this.ingredientInput = '';
    await this.storage.saveIngredients(this.ingredients);
  }

  async clearIngredients(): Promise<void> {
    this.ingredients = [];
    this.recommendations = [];
    await this.storage.saveIngredients(this.ingredients);
  }

  async removeIngredient(id: string): Promise<void> {
    this.ingredients = this.ingredients.filter((i: Ingredient) => i.id !== id);
    await this.storage.saveIngredients(this.ingredients);
  }

  getRecommendations(): void {
    this.recommendations = DishRecommendService.recommendByIngredients(this.ingredients);
  }

  // ================= Filters =================
  selectMood(m: Mood | string): void {
    this.filterSelections = this.filterSelections.clone();
    this.filterSelections.mood = this.filterSelections.mood === m ? '' : m;
  }

  selectTime(t: string): void {
    this.filterSelections = this.filterSelections.clone();
    this.filterSelections.time = this.filterSelections.time === t ? '' : t;
  }

  selectCuisine(c: string): void {
    this.filterSelections = this.filterSelections.clone();
    this.filterSelections.cuisine = this.filterSelections.cuisine === c ? '' : c;
  }

  selectCookingMethod(cm: string): void {
    this.filterSelections = this.filterSelections.clone();
    this.filterSelections.cookingMethod = this.filterSelections.cookingMethod === cm ? '' : cm;
  }

  applyFilters(): void {
    this.filterResults = DishRecommendService.filterBySelections(this.filterSelections);
  }

  resetFilters(): void {
    this.filterSelections = new FilterSelections();
    this.filterResults = [];
  }

  filterResultCount(): number {
    return this.filterResults.length;
  }

  // ================= Check-in =================
  todayMeals(): MealStatus[] {
    return CheckInService.todayMeals(this.checkins);
  }

  monthlyCount(): number {
    return CheckInService.monthlyCount(this.checkins);
  }

  history(limit: number = 30): CheckIn[] {
    return CheckInService.history(this.checkins, limit);
  }

  openCheckinForm(slot: MealSlot): void {
    this.checkinActiveMeal = slot;
    const existing: CheckIn | undefined = this.checkins
      .filter((c: CheckIn) => c.date === DateUtil.todayKey() && c.slot === slot)
      .pop();
    this.checkinDish = existing ? existing.dish : '';
    this.checkinMood = existing ? existing.mood : Mood.Treat;
    this.checkinTag = existing ? existing.tag : CheckInTag.HomeCooked;
    this.checkinFormOpen = true;
  }

  cancelCheckin(): void {
    this.checkinFormOpen = false;
    this.checkinDish = '';
  }

  async saveCheckin(): Promise<void> {
    const dish: string = this.checkinDish.trim();
    if (dish.length === 0) {
      this.cancelCheckin();
      return;
    }
    const todayKey: string = DateUtil.todayKey();
    const others: CheckIn[] = this.checkins.filter(
      (c: CheckIn) => !(c.date === todayKey && c.slot === this.checkinActiveMeal)
    );
    const record: CheckIn = new CheckIn({
      id: this.nextId('checkin'),
      date: todayKey,
      slot: this.checkinActiveMeal,
      dish,
      tag: this.checkinTag,
      mood: this.checkinMood,
      photoUri: '',
    });
    this.checkins = [...others, record];
    await this.storage.saveCheckins(this.checkins);
    this.checkinFormOpen = false;
    this.checkinDish = '';
  }

  // ================= Share =================
  openShareFromCheckin(): void {
    const latest: CheckIn | null = CheckInService.latest(this.checkins);
    if (latest === null) {
      return;
    }
    this.shareSource = { kind: 'checkin', checkin: latest };
    this.shareCaption = '';
    this.shareTemplate = ShareTemplate.Warm;
    this.refreshShareCard();
  }

  openShareFromWheel(tag: CheckInTag = CheckInTag.HomeCooked): void {
    if (this.wheelResult.length === 0) {
      return;
    }
    this.shareSource = { kind: 'wheel', dish: this.wheelResult, tag };
    this.shareCaption = '';
    this.shareTemplate = ShareTemplate.Warm;
    this.refreshShareCard();
  }

  setShareCaption(text: string): void {
    this.shareCaption = text;
    this.refreshShareCard();
  }

  selectShareTemplate(t: ShareTemplate): void {
    this.shareTemplate = t;
    this.refreshShareCard();
  }

  shareTemplateLabel(): string {
    return SHARE_TEMPLATE_LABELS[this.shareTemplate] ?? this.shareTemplate;
  }

  private refreshShareCard(): void {
    if (this.shareSource === null) {
      this.shareCard = null;
      return;
    }
    this.shareCard = ShareService.buildCardData(this.shareSource, this.shareCaption, this.shareTemplate);
  }

  async saveShareCardToAlbum(): Promise<string> {
    return ShareService.saveToAlbum();
  }

  async shareCurrentCard(): Promise<string> {
    return ShareService.shareCard();
  }

  // ================= Profile =================
  async clearAllData(): Promise<void> {
    await this.storage.clearAll();
    this.ingredients = [];
    this.checkins = [];
    this.wheelCandidates = [];
    this.recommendations = [];
    this.filterResults = [];
    this.filterSelections = new FilterSelections();
    this.wheelState = WheelState.Idle;
    this.wheelResult = '';
    this.shareCard = null;
    this.shareSource = null;
    this.userName = '美食家';
  }
}

