// Share card data assembly + system share/save dispatch hooks.
// The actual Canvas render + system share invocation happens in the visual
// phase; this service owns the data contract and template switching.
import { CHECK_IN_TAG_LABELS, CheckInTag, SHARE_TEMPLATE_LABELS, ShareTemplate } from '../common/Enums';
import { CheckIn, ShareCardData, ShareCardDataShape } from '../model/Models';
import { DateUtil } from '../util/DateUtil';

export interface CheckinShareSource {
  kind: 'checkin';
  checkin: CheckIn;
}

export interface WheelShareSource {
  kind: 'wheel';
  dish: string;
  tag: CheckInTag;
}

export type ShareSource = CheckinShareSource | WheelShareSource;

export class ShareService {
  static templates(): ShareTemplate[] {
    return [ShareTemplate.Warm, ShareTemplate.Fresh, ShareTemplate.Classic];
  }

  static templateLabel(t: ShareTemplate): string {
    return SHARE_TEMPLATE_LABELS[t] ?? t;
  }

  static checkinSource(checkin: CheckIn): CheckinShareSource {
    return { kind: 'checkin', checkin };
  }

  static wheelSource(dish: string, tag: CheckInTag): WheelShareSource {
    return { kind: 'wheel', dish, tag };
  }

  static buildCardData(source: ShareSource, caption: string, template: ShareTemplate): ShareCardData {
    if (source.kind === 'checkin') {
      const shape: ShareCardDataShape = {
        date: DateUtil.prettyLabel(new Date(parseDateMs(source.checkin.date))),
        dish: source.checkin.dish,
        caption,
        tag: CHECK_IN_TAG_LABELS[source.checkin.tag] ?? source.checkin.tag,
        template,
      };
      return new ShareCardData(shape);
    }
    const shape: ShareCardDataShape = {
      date: DateUtil.prettyLabel(),
      dish: source.dish,
      caption,
      tag: CHECK_IN_TAG_LABELS[source.tag] ?? source.tag,
      template,
    };
    return new ShareCardData(shape);
  }

  // Visual-phase dispatch hooks. Returns a status string the caller can surface
  // as feedback until Canvas/system-share wiring is implemented.
  static async saveToAlbum(): Promise<string> {
    return '已准备保存到相册（视觉阶段接入 Canvas 渲染）';
  }

  static async shareCard(): Promise<string> {
    return '已准备调用系统分享（视觉阶段接入系统分享面板）';
  }
}

// Parse YYYY-MM-DD into a millisecond timestamp for Date construction.
function parseDateMs(key: string): number {
  const parts: string[] = key.split('-');
  if (parts.length !== 3) {
    return Date.now();
  }
  return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
}

