// Wheel spin result + rotation computation. The visual Canvas/animation is
// owned by the UI layer; this service only decides the chosen candidate and
// the target rotation angle so the controller can drive the animation.
import { WheelCandidate } from '../model/Models';
import { WheelState } from '../common/Enums';

export interface SpinPlan {
  winner: WheelCandidate;
  winnerIndex: number;
  targetRotation: number; // degrees, accumulates full turns + offset
}

export class WheelService {
  static readonly MIN_CANDIDATES: number = 2;
  static readonly FULL_TURNS: number = 5;

  static canSpin(candidates: WheelCandidate[]): boolean {
    return candidates.length >= WheelService.MIN_CANDIDATES;
  }

  // Returns null if there are fewer than MIN_CANDIDATES.
  static planSpin(candidates: WheelCandidate[], currentRotation: number = 0): SpinPlan | null {
    if (!WheelService.canSpin(candidates)) {
      return null;
    }
    const winnerIndex: number = WheelService.randomInt(candidates.length);
    const winner: WheelCandidate = candidates[winnerIndex];
    const slice: number = 360 / candidates.length;
    // Land the pointer at the middle of the winner slice.
    const sliceCenter: number = winnerIndex * slice + slice / 2;
    const turns: number = WheelService.FULL_TURNS * 360;
    const target: number = currentRotation + turns + (360 - sliceCenter);
    return { winner, winnerIndex, targetRotation: target };
  }

  static stateAfterStop(prev: WheelState): WheelState {
    return WheelState.Stopped;
  }

  // [0, max). Uses Math.random; runtime randomness is acceptable here because
  // this is app runtime code, not the deterministic workflow sandbox.
  private static randomInt(max: number): number {
    return Math.floor(Math.random() * max);
  }
}

