  if (this.wheelState !== WheelState.Spinning) {
    return;
  }
  this.finishSpin();
}

spinAgain(): void {
  this.startSpin();
}

// Color used to paint wheel sector i (cycles through the palette).
wheelSectorColor(index: number): string {
  return WHEEL_SECTOR_COLORS[index % WHEEL_SECTOR_COLORS.length];
}

