// Reusable UI building blocks shared across 今天吃什么 pages.
import { Theme } from './Theme';
import { SvgIcon } from './SvgIcon';

@Component
export struct Chip {
  @Prop label: string;
  @Prop selected: boolean;
  selectedColor: string = Theme.tomato;
  onTap: () => void = () => {};

  build() {
    Text(this.label)
      .fontSize(14)
      .fontWeight(FontWeight.Medium)
      .fontColor(this.selected ? Theme.textOnBrand : Theme.textSecondary)
      .backgroundColor(this.selected ? this.selectedColor : Theme.tintNeutral)
      .padding({ left: 16, right: 16, top: 10, bottom: 10 })
      .borderRadius(Theme.radiusChip)
      .shadow(this.selected
        ? { radius: 10, color: 'rgba(43,38,34,0.12)', offsetX: 0, offsetY: 3 } as ShadowOptions
        : { radius: 0, color: '#00000000', offsetX: 0, offsetY: 0 } as ShadowOptions)
      .onClick(() => this.onTap());
  }
}

@Component
export struct TopBar {
  @Prop title: string;
  onBack: () => void = () => {};

  build() {
    Row({ space: 14 }) {
      CircleButton({ variant: 'back', onTap: () => this.onBack() })
      Text(this.title)
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Blank()
    }
    .width('100%')
    .height(44)
    .margin({ bottom: 22 })
    .alignItems(VerticalAlign.Center);
  }
}

@Component
export struct CircleButton {
  @Prop variant: string;
  onTap: () => void = () => {};

  build() {
    Stack() {
      SvgIcon({ variant: this.variant, iconSize: 22, color: Theme.textPrimary, strokeWidth: 2 })
    }
    .width(44)
    .height(44)
    .borderRadius(22)
    .backgroundColor('rgba(255,255,255,0.82)')
    .border({ width: 0.5, color: Theme.lineSoft })
    .shadow({ radius: 10, color: 'rgba(43,38,34,0.08)', offsetX: 0, offsetY: 2 } as ShadowOptions)
    .onClick(() => this.onTap());
  }
}

@Component
export struct PrimaryButton {
  @Prop label: string;
  @Prop iconVariant: string = '';
  onTap: () => void = () => {};

  build() {
    Row({ space: 8 }) {
      if (this.iconVariant.length > 0) {
        SvgIcon({ variant: this.iconVariant, iconSize: 18, color: Theme.textOnBrand, strokeWidth: 2.4 })
      }
      Text(this.label)
        .fontSize(15)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textOnBrand)
    }
    .padding({ left: 28, right: 28, top: 14, bottom: 14 })
    .borderRadius(Theme.radiusButton)
    .linearGradient({
      angle: 90,
      direction: GradientDirection.Right,
      colors: [[Theme.tomato, 0.0], [Theme.caramel, 1.0]],
    } as LinearGradient)
    .shadow(Theme.brandShadow)
    .justifyContent(FlexAlign.Center)
    .onClick(() => this.onTap());
  }
}

@Component
export struct SecondaryButton {
  @Prop label: string;
  @Prop iconVariant: string = '';
  onTap: () => void = () => {};

  build() {
    Row({ space: 8 }) {
      if (this.iconVariant.length > 0) {
        SvgIcon({ variant: this.iconVariant, iconSize: 18, color: Theme.tomato, strokeWidth: 2 })
      }
      Text(this.label)
        .fontSize(15)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.tomato)
    }
    .padding({ left: 28, right: 28, top: 13, bottom: 13 })
    .borderRadius(Theme.radiusButton)
    .backgroundColor('#FFFFFF')
    .border({ width: 1.5, color: Theme.borderTomatoSoft })
    .justifyContent(FlexAlign.Center)
    .onClick(() => this.onTap());
  }
}

