import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { AppStore } from '../controller/AppStore';

@Component
export struct HomePage {
  @ObjectLink store: AppStore;
  onOpenWheel: () => void = () => {};
  onGoIngredients: () => void = () => {};
  onOpenFilters: () => void = () => {};
  onGoCheckin: () => void = () => {};

  build() {
    Column({ space: 18 }) {
      // Header
      Column({ space: 6 }) {
        Text(this.store.greeting())
          .id('home-greeting')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Text(this.store.todayLabel())
          .id('home-date-label')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textSecondary)
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
      .margin({ top: 8, bottom: 10 })

      // Hero wheel card
      Row({ space: 14 }) {
        Column({ space: 10 }) {
          Text('快速决定')
            .fontSize(13)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.tomato)
          Text('让转盘来决定')
            .fontSize(22)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
          Text('不知道吃什么？\n转一下，立刻有答案。')
            .fontSize(14)
            .fontColor(Theme.textSecondary)
            .lineHeight(21)
          Row({ space: 8 }) {
            SvgIcon({ variant: 'search', iconSize: 16, color: Theme.textOnBrand, strokeWidth: 2.4 })
            Text('开始转盘')
              .fontSize(15)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textOnBrand)
          }
          .padding({ left: 20, right: 20, top: 12, bottom: 12 })
          .borderRadius(Theme.radiusButton)
          .linearGradient(BrandGradient.brand)
          .shadow(Theme.brandShadow)
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)

        this.HeroWheel()
      }
      .id('home-wheel-card')
      .width('100%')
      .padding(24)
      .borderRadius(Theme.radiusHero)
      .linearGradient(BrandGradient.hero)
      .shadow(Theme.heroShadow)
      .onClick(() => this.onOpenWheel())

      // Quick entries
      Row({ space: 12 }) {
        this.QuickCard('home-ingredients-card', Theme.avocado, Theme.tintAvocado, 'store', '冰箱食材', '有什么做什么', () => this.onGoIngredients())
        this.QuickCard('home-filters-card', Theme.mist, Theme.tintMist, 'favorite', '心情筛选', '找到对味的', () => this.onOpenFilters())
        this.QuickCard('home-checkin-button', Theme.caramel, Theme.tintCaramel, 'orders', '饮食打卡', '记录每一餐', () => this.onGoCheckin())
      }
      .width('100%')

      // Summary card
      Row() {
        Column({ space: 8 }) {
          Text('今日打卡')
            .id('home-checkin-summary')
            .fontSize(16)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
          Row({ space: 6 }) {
            ForEach([0, 1, 2, 3], (i: number) => {
              Circle()
                .width(10)
                .height(10)
                .fill(i < this.store.todaySummary().completed ? Theme.avocado : Theme.line)
            }, (i: number) => `${i}`)
          }
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)

        Column({ space: 4 }) {
          Text(`${this.store.streak()}`)
            .id('home-streak-count')
            .fontSize(26)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.avocado)
          Text('连续打卡')
            .fontSize(11)
            .fontColor(Theme.textSecondary)
        }
        .padding({ left: 16, right: 16, top: 10, bottom: 10 })
        .borderRadius(16)
        .linearGradient(BrandGradient.success)
        .border({ width: 0.5, color: Theme.borderAvocadoSoft })
      }
      .width('100%')
      .padding({ left: 20, right: 20, top: 18, bottom: 18 })
      .borderRadius(Theme.radiusCard)
      .linearGradient(BrandGradient.card)
      .shadow(Theme.cardShadow)
      .border({ width: 0.5, color: Theme.lineSoft })
    }
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 12 })
  }

  @Builder
  HeroWheel() {
    Stack() {
      Circle().width(96).height(96).fill('#FFFFFF').stroke(Theme.line)
      Circle().width(96).height(96).fill('rgba(0,0,0,0)')
      // decorative sectors approximated with stacked arcs
      Stack() {
        Path()
          .commands('M48 4 A44 44 0 0 1 92 48 L48 48 Z')
          .fill(Theme.lemon)
        Path()
          .commands('M92 48 A44 44 0 0 1 48 92 L48 48 Z')
          .fill('#FFF5D9')
        Path()
          .commands('M48 92 A44 44 0 0 1 4 48 L48 48 Z')
          .fill(Theme.tomato)
        Path()
          .commands('M4 48 A44 44 0 0 1 48 4 L48 48 Z')
          .fill(Theme.tintAvocado)
      }
      .width(96)
      .height(96)
      Circle().width(34).height(34).fill('#FFFFFF')
      Circle().width(34).height(34).fill('rgba(0,0,0,0)')
        .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
    }
    .width(110)
    .height(110)
  }

  @Builder
  QuickCard(idValue: string, color: string, bg: string, icon: string, title: string, hint: string, onTap: () => void) {
    Column({ space: 10 }) {
      Stack() {
        SvgIcon({ variant: icon, iconSize: 22, color: color, strokeWidth: 2.2 })
      }
      .width(40)
      .height(40)
      .borderRadius(12)
      .backgroundColor(bg)
      Text(title)
        .fontSize(14)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Text(hint)
        .fontSize(11)
        .fontColor(Theme.textTertiary)
    }
    .id(idValue)
    .layoutWeight(1)
    .padding({ top: 16, bottom: 16 })
    .borderRadius(Theme.radiusCard)
    .linearGradient(BrandGradient.card)
    .shadow(Theme.cardShadow)
    .border({ width: 0.5, color: Theme.lineSoft })
    .onClick(() => onTap())
  }
}

