          .rotate({ angle: this.store.wheelRotation })

          // Pointer (fixed, pointing down into the wheel top)
          Stack() {
            Path()
              .commands('M14 0 L28 26 L20 22 L14 30 L8 22 L0 26 Z')
              .fill(Theme.tomato)
          }
          .width(28)
