import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { PrimaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { Ingredient, Recommendation } from '../model/Models';
import { DIFFICULTY_LABELS } from '../model/Models';

@Component
export struct IngredientsPage {
  @ObjectLink store: AppStore;

  build() {
    Column({ space: 16 }) {
      Column({ space: 6 }) {
        Text('冰箱食材')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Text('输入你现有的食材，帮你推荐能做什么')
          .fontSize(15)
          .fontColor(Theme.textSecondary)
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
      .margin({ top: 8 })

      // Input row
      Row({ space: 10 }) {
        TextInput({ text: this.store.ingredientInput, placeholder: '例如：鸡蛋、番茄、牛肉' })
          .id('ingredients-input')
          .layoutWeight(1)
          .height(50)
          .fontSize(15)
          .fontColor(Theme.textPrimary)
          .backgroundColor(Theme.cardBgAlt)
          .borderRadius(16)
          .border({ width: 1.5, color: Theme.line })
          .padding({ left: 16, right: 16 })
          .onChange((v: string) => { this.store.ingredientInput = v; })
        Stack() {
          SvgIcon({ variant: 'add', iconSize: 22, color: Theme.textOnBrand, strokeWidth: 2.5 })
        }
        .id('ingredients-add-button')
        .width(50).height(50).borderRadius(16)
        .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
        .shadow(Theme.brandShadow)
        .onClick(() => { this.store.addIngredient(); })
      }
      .width('100%')

      // Ingredient tags
      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(this.store.ingredients, (ing: Ingredient) => {
          Row({ space: 6 }) {
            Text(ing.name).fontSize(14).fontWeight(FontWeight.Medium).fontColor(Theme.textSecondary)
            Stack() {
              SvgIcon({ variant: 'trash', iconSize: 14, color: Theme.textTertiary, strokeWidth: 2 })
            }
            .width(20).height(20)
            .onClick(() => { this.store.removeIngredient(ing.id); })
          }
          .id(`ingredient-${ing.id}`)
          .padding({ left: 14, right: 12, top: 8, bottom: 8 })
          .margin({ right: 10, bottom: 10 })
          .borderRadius(12)
          .backgroundColor(Theme.tintNeutral)
        }, (ing: Ingredient) => ing.id)
      }
      .id('ingredients-list')
      .width('100%')

      // Section header
      Row() {
        Text('推荐菜谱')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Blank()
        Text('清空食材')
          .id('ingredients-clear-button')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
          .onClick(() => { this.store.clearIngredients(); })
      }
      .width('100%')

      // Recommend list / empty
      if (this.store.ingredients.length === 0) {
        this.EmptyState()
      } else if (this.store.recommendations.length === 0) {
        Column() {
          Text('点击下方按钮，根据食材生成推荐')
            .id('ingredients-recommend-empty')
            .fontSize(14)
            .fontColor(Theme.textTertiary)
        }
        .width('100%').padding(24).alignItems(HorizontalAlign.Center)
      } else {
        Column({ space: 12 }) {
          ForEach(this.store.recommendations, (rec: Recommendation) => {
            Row({ space: 14 }) {
              Stack() {
                SvgIcon({ variant: 'placeholder', iconSize: 26, color: Theme.caramel, strokeWidth: 2 })
              }
              .width(48).height(48).borderRadius(14).backgroundColor(Theme.tintCaramel)
              Column({ space: 4 }) {
                Text(rec.dish.name)
                  .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
                Text(`需要：${rec.dish.ingredients.join('、')} · 难度：${DIFFICULTY_LABELS[rec.dish.difficulty] ?? rec.dish.difficulty}`)
                  .fontSize(13).fontColor(Theme.textSecondary).maxLines(1)
              }
              .alignItems(HorizontalAlign.Start).layoutWeight(1)
              this.MatchRing(rec.match)
            }
            .id(`recommendation-${rec.dish.id}`)
            .width('100%').padding(18).borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBgAlt)
            .shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })
          }, (rec: Recommendation) => rec.dish.id)
        }
        .id('ingredients-recommend-list')
        .width('100%')
      }

      PrimaryButton({
        label: '重新推荐',
        iconVariant: 'search',
        onTap: () => { this.store.getRecommendations(); },
      })
        .width('100%')
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 100 })
  }

  @Builder
  EmptyState() {
    Column({ space: 10 }) {
      Stack() {
        SvgIcon({ variant: 'store', iconSize: 56, color: Theme.line, strokeWidth: 1.5 })
      }
      .width(80).height(80)
      Text('还没有食材')
        .fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
      Text('添加冰箱里的食材，立刻获得菜谱推荐')
        .fontSize(14).fontColor(Theme.textSecondary)
    }
    .id('ingredients-empty-state')
    .width('100%').padding({ top: 36, bottom: 36 }).alignItems(HorizontalAlign.Center)
  }

  @Builder
  MatchRing(match: number) {
    Stack() {
      Circle().width(46).height(46)
        .fill('rgba(0,0,0,0)')
        .stroke(Theme.line).strokeWidth(4)
      Progress({ value: match * 100, total: 100, type: ProgressType.Ring })
        .width(46).height(46)
        .color(Theme.avocado)
        .style({ strokeWidth: 4 } as ProgressStyleOptions)
      Text(`${Math.round(match * 100)}%`)
        .fontSize(11).fontWeight(FontWeight.Bold).fontColor(Theme.avocado)
    }
    .width(46).height(46)
  }
}

