import { Theme } from '../common/Theme';
import { Chip, TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { Mood, MealTime, Cuisine } from '../common/Enums';
import { MOOD_LABELS, MEAL_TIME_LABELS, CUISINE_LABELS } from '../common/Enums';
import { FilterResult } from '../model/Models';

@Component
export struct FiltersPage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};

  private moodColor(m: Mood): string {
    if (m === Mood.Healthy) {
      return Theme.avocado;
    } else if (m === Mood.Treat) {
      return Theme.tomato;
    } else if (m === Mood.Budget) {
      return Theme.caramel;
    } else if (m === Mood.Lazy) {
      return Theme.mist;
    }
    return Theme.grape;
  }

  build() {
    Column({ space: 16 }) {
      TopBar({ title: '心情 / 时间筛选', onBack: () => this.onBack() })

      // Mood group
      Column({ space: 14 }) {
        Text('现在的心情')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([Mood.Healthy, Mood.Treat, Mood.Budget, Mood.Lazy, Mood.Adventurous], (m: Mood) => {
            Chip({
              label: MOOD_LABELS[m] ?? m,
              selected: this.store.filterSelections.mood === m,
              selectedColor: this.moodColor(m),
              onTap: () => { this.store.selectMood(m); },
            })
          }, (m: Mood) => m)
        }
        .id('filters-mood-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Time group
      Column({ space: 14 }) {
        Text('用餐时段')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([MealTime.Breakfast, MealTime.Lunch, MealTime.Dinner, MealTime.LateNight, MealTime.Tea], (t: MealTime) => {
            Chip({
              label: MEAL_TIME_LABELS[t] ?? t,
              selected: this.store.filterSelections.time === t,
              selectedColor: Theme.tomato,
              onTap: () => { this.store.selectTime(t); },
            })
          }, (t: MealTime) => t)
        }
        .id('filters-time-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Cuisine group
      Column({ space: 14 }) {
        Text('菜系偏好（可选）')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([Cuisine.Chinese, Cuisine.Western, Cuisine.Japanese, Cuisine.Korean, Cuisine.Light], (c: Cuisine) => {
            Chip({
              label: CUISINE_LABELS[c] ?? c,
              selected: this.store.filterSelections.cuisine === c,
              selectedColor: Theme.tomato,
              onTap: () => { this.store.selectCuisine(c); },
            })
          }, (c: Cuisine) => c)
        }
        .id('filters-cuisine-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Result header
      Row() {
        Text('为你找到')
          .fontSize(18).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Blank()
        Text(`${this.store.filterResultCount()} 个结果`)
          .id('filters-result-count')
          .fontSize(13).fontColor(Theme.textSecondary)
      }
      .width('100%')

      // Result grid
      if (this.store.filterResults.length === 0) {
        Text('选择条件后点击“应用筛选”查看结果')
          .id('filters-no-results')
          .fontSize(14).fontColor(Theme.textTertiary)
          .width('100%').padding(24).textAlign(TextAlign.Center)
      } else {
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach(this.store.filterResults, (r: FilterResult) => {
            Column({ space: 4 }) {
              Text(r.dish.name)
                .fontSize(15).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
              Row({ space: 4 }) {
                ForEach(r.tags.slice(0, 2), (tag: string, idx: number) => {
                  Text(tag)
                    .fontSize(10).fontColor(Theme.textSecondary)
                    .padding({ left: 8, right: 8, top: 3, bottom: 3 })
                    .borderRadius(6).backgroundColor(Theme.tintNeutral)
                }, (tag: string) => tag)
              }
            }
            .id(`filter-result-${r.dish.id}`)
            .width('46%')
            .margin({ right: 12, bottom: 12 })
            .padding(16)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBgAlt)
            .shadow(Theme.cardShadow)
            .border({ width: 0.5, color: Theme.lineSoft })
            .alignItems(HorizontalAlign.Center)
          }, (r: FilterResult) => r.dish.id)
        }
        .id('filters-result-list')
        .width('100%')
      }

      // Bottom actions
      Row({ space: 12 }) {
        SecondaryButton({ label: '重置', onTap: () => { this.store.resetFilters(); } })
          .id('filters-reset-button')
          .width(110)
        PrimaryButton({
          label: '应用筛选',
          iconVariant: 'search',
          onTap: () => { this.store.applyFilters(); },
        })
          .id('filters-apply-button')
          .layoutWeight(1)
      }
      .width('100%')
      .margin({ top: 4 })
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }
}

