import { TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { ShareService } from '../service/ShareService';
import { ShareTemplate } from '../common/Enums';

@Component
export struct SharePage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};

  private templateGrad(t: ShareTemplate): LinearGradient {
    if (t === ShareTemplate.Fresh) {
      return { angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tintAvocado, 0], [Theme.tintMist, 1]] } as LinearGradient;
    } else if (t === ShareTemplate.Classic) {
      return { angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.textPrimary, 0], ['#4A423A', 1]] } as LinearGradient;
    }
    return BrandGradient.hero;
  }

  private async onSave(): Promise<void> {
    const msg: string = await this.store.saveShareCardToAlbum();
    promptAction.showToast({ message: msg });
  }

  private async onShare(): Promise<void> {
    const msg: string = await this.store.shareCurrentCard();
    promptAction.showToast({ message: msg });
  }

  build() {
    Column({ space: 18 }) {
      TopBar({ title: '分享今日美食', onBack: () => this.onBack() })

      // Card preview
      Stack() {
        // decorative circles
        Circle().width(180).height(180).fill('rgba(255,216,92,0.35)')
          .position({ x: '62%', y: -60 })
        Circle().width(220).height(220).fill('rgba(232,85,69,0.12)')
          .position({ x: -60, y: '72%' })

        Column({ space: 14 }) {
          Blank().layoutWeight(1)
          Column({ space: 14 }) {
            Text(this.store.shareCard ? this.store.shareCard.date : this.store.todayLabel())
              .fontSize(13).fontColor(Theme.textSecondary)
            Text(this.store.shareCard ? this.store.shareCard.dish : '今天吃什么')
              .fontSize(34).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
            Text(this.store.shareCard && this.store.shareCard.caption.length > 0
              ? this.store.shareCard.caption : '写一句心情，记录这一餐的小确幸。')
              .fontSize(15).fontColor(Theme.textSecondary)
              .padding(16)
              .borderRadius(16)
              .backgroundColor('rgba(255,255,255,0.72)')
            Row({ space: 8 }) {
              if (this.store.shareCard) {
                Text(`#${this.store.shareCard.tag}`)
                  .fontSize(12).fontWeight(FontWeight.Medium).fontColor(Theme.tomato)
                  .padding({ left: 12, right: 12, top: 6, bottom: 6 })
                  .borderRadius(20).backgroundColor('#FFFFFF')
              }
            }
          }
          .alignItems(HorizontalAlign.Start)
          .width('100%')
          Blank().layoutWeight(1)
          Text('今天吃什么 · 记录每一餐')
            .fontSize(12).fontColor(Theme.textTertiary)
            .width('100%').textAlign(TextAlign.End)
        }
        .width('100%').height('100%').padding(28)
      }
      .id('share-card-preview')
      .width('100%')
      .height(460)
      .borderRadius(Theme.radiusHero)
      .linearGradient(this.templateGrad(this.store.shareTemplate))
      .shadow(Theme.heroShadow)
      .clip(true)

      // Caption input
      TextInput({ text: this.store.shareCaption, placeholder: '写一句心情...' })
        .id('share-caption-input')
        .width('100%')
        .fontSize(15)
        .fontColor(Theme.textPrimary)
        .backgroundColor(Theme.cardBgAlt)
        .borderRadius(Theme.radiusButton)
        .border({ width: 1.5, color: Theme.line })
        .padding({ left: 16, right: 16, top: 14, bottom: 14 })
        .onChange((v: string) => { this.store.setShareCaption(v); })

      // Template selector
      Row({ space: 10 }) {
        ForEach(ShareService.templates(), (t: ShareTemplate) => {
          Stack()
            .width(44).height(44).borderRadius(12)
            .border({ width: this.store.shareTemplate === t ? 2 : 0, color: Theme.tomato })
            .linearGradient(this.templateGrad(t))
            .onClick(() => { this.store.selectShareTemplate(t); })
        }, (t: ShareTemplate) => t)
      }
      .id('share-template-selector')
      .width('100%')
      .justifyContent(FlexAlign.Center)
      .margin({ bottom: 4 })

      // Actions
      Row({ space: 12 }) {
        SecondaryButton({ label: '保存到相册', iconVariant: 'card', onTap: () => { this.onSave(); } })
          .id('share-save-button')
          .layoutWeight(1)
        PrimaryButton({ label: '分享', iconVariant: 'card', onTap: () => { this.onShare(); } })
          .id('share-send-button')
          .layoutWeight(1)
      }
      .width('100%')
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }
}

import { ShareService } from '../service/ShareService';

