import { promptAction } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { AppStore } from '../controller/AppStore';

@Component
export struct ProfilePage {
  @ObjectLink store: AppStore;

  private async onClearData(): Promise<void> {
    await this.store.clearAllData();
    promptAction.showToast({ message: '已清空所有本地数据' });
  }

  build() {
    Column({ space: 24 }) {
      Text('我的')
        .fontSize(28).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        .width('100%')
        .margin({ top: 8 })

      // Profile card
      Row({ space: 18 }) {
        Stack() {
          SvgIcon({ variant: 'profile', iconSize: 32, color: Theme.caramel, strokeWidth: 2 })
        }
        .width(64).height(64).borderRadius(32).backgroundColor('#FFFFFF')
        .shadow({ radius: 12, color: 'rgba(43,38,34,0.08)', offsetX: 0, offsetY: 4 } as ShadowOptions)
        Column({ space: 4 }) {
          Text(this.store.userName)
            .id('profile-username')
            .fontSize(20).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
          Text(`已连续打卡 ${this.store.streak()} 天 · 本月 ${this.store.monthlyCount()} 次`)
            .fontSize(13).fontColor(Theme.textSecondary)
        }
        .alignItems(HorizontalAlign.Start)
      }
      .width('100%').padding(26).borderRadius(Theme.radiusHero)
      .linearGradient(BrandGradient.hero).shadow(Theme.heroShadow)

      // Menu list
      Column({ space: 0 }) {
        this.MenuItem('profile-dish-library-button', Theme.caramel, Theme.tintCaramel, 'info', '菜品库', () => {
          promptAction.showToast({ message: '菜品库即将开放' });
        })
        this.MenuItem('profile-settings-button', Theme.mist, Theme.tintMist, 'settings', '设置', () => {
          promptAction.showToast({ message: '设置即将开放' });
        })
        this.MenuItem('profile-clear-data-button', Theme.tomato, Theme.tintTomato, 'trash', '清空所有数据', () => {
          this.onClearData();
        }, true)
        this.MenuItem('profile-version-label', Theme.textSecondary, Theme.tintNeutral, 'info', '关于 今天吃什么 v1.0.0', () => {
          promptAction.showToast({ message: '今天吃什么 v1.0.0' });
        })
      }
      .width('100%')
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt)
      .shadow(Theme.cardShadow)
      .border({ width: 0.5, color: Theme.lineSoft })
      .clip(true)
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 100 })
  }

  @Builder
  MenuItem(idValue: string, color: string, bg: string, icon: string, label: string, onTap: () => void, danger: boolean = false) {
    Row({ space: 14 }) {
      Stack() {
        SvgIcon({ variant: icon, iconSize: 22, color: color, strokeWidth: 2 })
      }
      .width(40).height(40).borderRadius(12).backgroundColor(bg)
      Text(label)
        .fontSize(16).fontWeight(FontWeight.Medium)
        .fontColor(danger ? Theme.tomato : Theme.textPrimary)
        .layoutWeight(1)
      SvgIcon({ variant: 'arrowRight', iconSize: 18, color: Theme.textTertiary, strokeWidth: 2 })
    }
    .id(idValue)
    .width('100%')
    .padding({ left: 20, right: 20, top: 18, bottom: 18 })
    .border({ width: { bottom: 0.5 }, color: { bottom: Theme.line } })
    .onClick(() => onTap())
  }
}

