import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { PrimaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';

@Component
export struct WheelEditorSheet {
  @ObjectLink store: AppStore;

  build() {
    Column({ space: 0 }) {
      Row() {
        Text('编辑候选菜')
          .fontSize(20).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
          .layoutWeight(1)
        Stack() {
          SvgIcon({ variant: 'trash', iconSize: 22, color: Theme.textPrimary, strokeWidth: 2 })
        }
        .id('wheel-editor-close-button')
        .width(44).height(44).borderRadius(22)
        .backgroundColor('rgba(255,255,255,0.82)')
        .border({ width: 0.5, color: Theme.lineSoft })
        .onClick(() => { this.store.closeWheelEditor(); })
      }
      .width('100%')
      .margin({ bottom: 24 })

      Column({ space: 20 }) {
        Column({ space: 10 }) {
          Text('菜品名称')
            .fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary)
            .width('100%')
          TextInput({ text: this.store.editorDraft, placeholder: '输入菜品名称' })
            .id('wheel-editor-input')
            .width('100%').height(50).fontSize(15)
            .fontColor(Theme.textPrimary)
            .backgroundColor(Theme.cardBgAlt)
            .borderRadius(Theme.radiusButton)
            .border({ width: 1.5, color: Theme.line })
            .padding({ left: 18, right: 18 })
            .onChange((v: string) => { this.store.editorDraft = v; })
        }
        .width('100%')

        Row({ space: 12 }) {
          if (this.store.editorEditingId.length > 0) {
            Text('删除')
              .id('wheel-editor-delete-button')
              .fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.tomato)
              .layoutWeight(1).textAlign(TextAlign.Center)
              .padding({ top: 14, bottom: 14 })
              .borderRadius(Theme.radiusButton)
              .backgroundColor('#FFFFFF')
              .border({ width: 1.5, color: Theme.borderTomatoSoft })
              .onClick(async () => {
                await this.store.deleteWheelCandidate(this.store.editorEditingId);
                this.store.closeWheelEditor();
              })
          }
          Text('保存')
            .id('wheel-editor-save-button')
            .fontSize(15).fontWeight(FontWeight.Bold).fontColor(Theme.textOnBrand)
            .layoutWeight(1).textAlign(TextAlign.Center)
            .padding({ top: 14, bottom: 14 })
            .borderRadius(Theme.radiusButton)
            .linearGradient(BrandGradient.brand)
            .shadow(Theme.brandShadow)
            .onClick(() => { this.store.saveWheelCandidate(); })
        }
        .width('100%')
        .margin({ top: 8 })
      }
      .width('100%')
      .padding(24)
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt)
      .shadow(Theme.cardShadow)
      .border({ width: 0.5, color: Theme.lineSoft })
    }
    .width('100%')
    .padding({ left: 22, right: 22, top: 48 })
  }
}

