          }
          .id('checkin-form-mood-group')
          .width('100%')
        }
        .width('100%')

        // Tag
        Column({ space: 10 }) {
          Text('标签').fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).width('100%')
