import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { WheelState } from '../common/Enums';
import { WheelCandidate } from '../model/Models';

const WHEEL_SIZE: number = 280;
const WHEEL_R: number = 138;
const WHEEL_C: number = 140;

@Component
export struct WheelPage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};
  onOpenShare: () => void = () => {};
  private n: number = 0;

  private sectorCmd(i: number): string {
    const slice: number = 360 / this.n;
    const a0: number = (i * slice) * Math.PI / 180;
    const a1: number = ((i + 1) * slice) * Math.PI / 180;
    const x0: number = WHEEL_C + WHEEL_R * Math.sin(a0);
    const y0: number = WHEEL_C - WHEEL_R * Math.cos(a0);
    const x1: number = WHEEL_C + WHEEL_R * Math.sin(a1);
    const y1: number = WHEEL_C - WHEEL_R * Math.cos(a1);
    const large: number = slice > 180 ? 1 : 0;
    return `M${WHEEL_C} ${WHEEL_C} L${x0.toFixed(2)} ${y0.toFixed(2)} A${WHEEL_R} ${WHEEL_R} 0 ${large} 1 ${x1.toFixed(2)} ${y1.toFixed(2)} Z`;
  }

  private labelX(i: number): number {
    const slice: number = 360 / this.n;
    const mid: number = (i * slice + slice / 2) * Math.PI / 180;
    return WHEEL_C + (WHEEL_R * 0.62) * Math.sin(mid);
  }

  private labelY(i: number): number {
    const slice: number = 360 / this.n;
    const mid: number = (i * slice + slice / 2) * Math.PI / 180;
    return WHEEL_C - (WHEEL_R * 0.62) * Math.cos(mid);
  }

  private startSpin(): void {
    if (!this.store.startSpin()) {
      return;
    }
    const store: AppStore = this.store;
    animateTo({
      duration: store.spinDurationMs(),
      curve: Curve.EaseOut,
      onFinish: () => store.finishSpin(),
    }, () => {
      store.wheelRotation = store.spinTarget();
    });
  }

  build() {
    this.n = this.store.wheelCandidates.length;
    Column({ space: 18 }) {
      TopBar({ title: '转盘抽菜', onBack: () => this.onBack() })

      Column({ space: 28 }) {
        // Wheel
        Stack() {
          Stack() {
            Circle().width(WHEEL_SIZE).height(WHEEL_SIZE).fill('#FFFFFF')
            ForEach(this.store.wheelCandidates, (c: WheelCandidate, i: number) => {
              Path()
                .commands(this.sectorCmd(i))
                .fill(this.store.wheelSectorColor(i))
                .stroke('#FFFFFF')
                .strokeWidth(1)
            }, (c: WheelCandidate) => c.id)
            ForEach(this.store.wheelCandidates, (c: WheelCandidate, i: number) => {
              Text(c.name)
                .fontSize(13)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.textPrimary)
                .maxLines(1)
                .position({ x: this.labelX(i) - 30, y: this.labelY(i) - 8 })
                .width(60)
                .textAlign(TextAlign.Center)
            }, (c: WheelCandidate) => `t-${c.id}`)
            Circle().width(74).height(74).fill('#FFFFFF')
          }
          .width(WHEEL_SIZE)
          .height(WHEEL_SIZE)
          .rotate({ angle: this.store.wheelRotation })

          // Pointer (fixed, pointing down into the wheel top)
          Stack() {
            Path()
              .commands('M14 0 L28 26 L20 22 L14 30 L8 22 L0 26 Z')
              .fill(Theme.tomato)
          }
          .width(28)
          .height(30)
          .position({ x: (WHEEL_SIZE - 28) / 2, y: -10 })

          // Center start button
          Text(this.store.wheelState === WheelState.Spinning ? '…' : '开始')
            .id('wheel-start-button')
            .fontSize(15)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textOnBrand)
            .width(70)
            .height(70)
            .textAlign(TextAlign.Center)
            .borderRadius(35)
            .border({ width: 3, color: '#FFFFFF' })
            .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
            .shadow({ radius: 24, color: 'rgba(232,85,69,0.35)', offsetX: 0, offsetY: 8 } as ShadowOptions)
            .onClick(() => this.startSpin())
        }
        .width(WHEEL_SIZE)
        .height(WHEEL_SIZE + 20)
        .id('wheel-canvas')
        .alignContent(Alignment.Center)

        // Result
        Column({ space: 6 }) {
          Text('转盘结果')
            .fontSize(13)
            .fontColor(Theme.textSecondary)
          Text(this.store.wheelResult.length > 0 ? this.store.wheelResult : '点击开始')
            .id('wheel-result-label')
            .fontSize(26)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.tomato)
        }
        .padding({ left: 32, right: 32, top: 20, bottom: 20 })
        .borderRadius(Theme.radiusCard)
        .backgroundColor('#FFFFFF')
        .shadow(Theme.cardShadow)
        .border({ width: 0.5, color: Theme.lineSoft })

        // Actions
        Column({ space: 12 }) {
          if (this.n < 2) {
            Text('至少添加 2 个候选菜才能开始转盘')
              .fontSize(13)
              .fontColor(Theme.textTertiary)
          } else {
            PrimaryButton({
              label: this.store.wheelState === WheelState.Spinning ? '旋转中…' : '开始转盘',
              iconVariant: 'search',
              onTap: () => this.startSpin(),
            })
          }
          SecondaryButton({
            label: '再转一次',
            iconVariant: 'favorite',
            onTap: () => { this.store.spinAgain(); this.startSpin(); },
          })
          if (this.store.wheelResult.length > 0) {
            Text('为此结果打卡')
              .id('wheel-checkin-button')
              .fontSize(14)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textSecondary)
              .padding({ top: 8, bottom: 8 })
              .onClick(() => {
                this.store.openShareFromWheel();
                this.onOpenShare();
              })
          }
        }

        // Candidate list
        this.CandidateList()
      }
      .width('100%')
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }

  @Builder
  CandidateList() {
    Column({ space: 0 }) {
      Row() {
        Text('候选菜品')
          .fontSize(16)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Blank()
        Text('编辑')
          .id('wheel-edit-button')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
          .padding({ top: 6, bottom: 6, left: 10, right: 10 })
          .onClick(() => this.store.openWheelEditor())
      }
      .width('100%')
      .margin({ bottom: 10 })

      if (this.store.wheelCandidates.length === 0) {
        Text('还没有候选菜，点击右上角“编辑”添加')
          .id('wheel-empty-candidates')
          .fontSize(14)
          .fontColor(Theme.textTertiary)
          .padding({ top: 18, bottom: 18 })
      } else {
        ForEach(this.store.wheelCandidates, (c: WheelCandidate) => {
          Row() {
            Text(c.name)
              .id(`wheel-candidate-${c.id}`)
              .fontSize(15)
              .fontColor(Theme.textPrimary)
              .layoutWeight(1)
            Row({ space: 8 }) {
              Stack() {
                SvgIcon({ variant: 'info', iconSize: 16, color: Theme.textSecondary, strokeWidth: 2 })
              }
              .width(32).height(32).borderRadius(8).backgroundColor(Theme.tintNeutral)
              .onClick(() => this.store.openWheelEditor(c.id))
              Stack() {
                SvgIcon({ variant: 'trash', iconSize: 16, color: Theme.textSecondary, strokeWidth: 2 })
              }
              .id('wheel-editor-delete-button')
              .width(32).height(32).borderRadius(8).backgroundColor(Theme.tintNeutral)
              .onClick(() => this.store.deleteWheelCandidate(c.id))
            }
          }
          .width('100%')
          .padding({ top: 12, bottom: 12 })
          .border({ width: { bottom: 0.5 }, color: { bottom: Theme.line } })
        }, (c: WheelCandidate) => c.id)
      }

      Row({ space: 8 }) {
        SvgIcon({ variant: 'add', iconSize: 18, color: Theme.tomato, strokeWidth: 2 })
        Text('添加候选菜')
          .id('wheel-add-candidate-button')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
      }
      .width('100%')
      .justifyContent(FlexAlign.Center)
      .padding({ top: 14, bottom: 6 })
      .border({ width: 1.5, color: Theme.borderTomatoSoft })
      .borderRadius(Theme.radiusButton)
      .backgroundColor('#FFFFFF')
      .margin({ top: 10 })
      .onClick(() => this.store.openWheelEditor())
    }
    .id('wheel-candidate-list')
    .width('100%')
    .padding(18)
    .borderRadius(Theme.radiusCard)
    .backgroundColor('#FFFFFF')
    .shadow(Theme.cardShadow)
    .border({ width: 0.5, color: Theme.lineSoft })
  }
}

import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { PrimaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { Ingredient, Recommendation } from '../model/Models';
import { DIFFICULTY_LABELS } from '../model/Models';

@Component
export struct IngredientsPage {
  @ObjectLink store: AppStore;

  build() {
    Column({ space: 16 }) {
      Column({ space: 6 }) {
        Text('冰箱食材')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Text('输入你现有的食材，帮你推荐能做什么')
          .fontSize(15)
          .fontColor(Theme.textSecondary)
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
      .margin({ top: 8 })

      // Input row
      Row({ space: 10 }) {
        TextInput({ text: this.store.ingredientInput, placeholder: '例如：鸡蛋、番茄、牛肉' })
          .id('ingredients-input')
          .layoutWeight(1)
          .height(50)
          .fontSize(15)
          .fontColor(Theme.textPrimary)
          .backgroundColor(Theme.cardBgAlt)
          .borderRadius(16)
          .border({ width: 1.5, color: Theme.line })
          .padding({ left: 16, right: 16 })
          .onChange((v: string) => { this.store.ingredientInput = v; })
        Stack() {
          SvgIcon({ variant: 'add', iconSize: 22, color: Theme.textOnBrand, strokeWidth: 2.5 })
        }
        .id('ingredients-add-button')
        .width(50).height(50).borderRadius(16)
        .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
        .shadow(Theme.brandShadow)
        .onClick(() => { this.store.addIngredient(); })
      }
      .width('100%')

      // Ingredient tags
      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(this.store.ingredients, (ing: Ingredient) => {
          Row({ space: 6 }) {
            Text(ing.name).fontSize(14).fontWeight(FontWeight.Medium).fontColor(Theme.textSecondary)
            Stack() {
              SvgIcon({ variant: 'trash', iconSize: 14, color: Theme.textTertiary, strokeWidth: 2 })
            }
            .width(20).height(20)
            .onClick(() => { this.store.removeIngredient(ing.id); })
          }
          .id(`ingredient-${ing.id}`)
          .padding({ left: 14, right: 12, top: 8, bottom: 8 })
          .margin({ right: 10, bottom: 10 })
          .borderRadius(12)
          .backgroundColor(Theme.tintNeutral)
        }, (ing: Ingredient) => ing.id)
      }
      .id('ingredients-list')
      .width('100%')

      // Section header
      Row() {
        Text('推荐菜谱')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Blank()
        Text('清空食材')
          .id('ingredients-clear-button')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
          .onClick(() => { this.store.clearIngredients(); })
      }
      .width('100%')

      // Recommend list / empty
      if (this.store.ingredients.length === 0) {
        this.EmptyState()
      } else if (this.store.recommendations.length === 0) {
        Column() {
          Text('点击下方按钮，根据食材生成推荐')
            .id('ingredients-recommend-empty')
            .fontSize(14)
            .fontColor(Theme.textTertiary)
        }
        .width('100%').padding(24).alignItems(HorizontalAlign.Center)
      } else {
        Column({ space: 12 }) {
          ForEach(this.store.recommendations, (rec: Recommendation) => {
            Row({ space: 14 }) {
              Stack() {
                SvgIcon({ variant: 'placeholder', iconSize: 26, color: Theme.caramel, strokeWidth: 2 })
              }
              .width(48).height(48).borderRadius(14).backgroundColor(Theme.tintCaramel)
              Column({ space: 4 }) {
                Text(rec.dish.name)
                  .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
                Text(`需要：${rec.dish.ingredients.join('、')} · 难度：${DIFFICULTY_LABELS[rec.dish.difficulty] ?? rec.dish.difficulty}`)
                  .fontSize(13).fontColor(Theme.textSecondary).maxLines(1)
              }
              .alignItems(HorizontalAlign.Start).layoutWeight(1)
              this.MatchRing(rec.match)
            }
            .id(`recommendation-${rec.dish.id}`)
            .width('100%').padding(18).borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBgAlt)
            .shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })
          }, (rec: Recommendation) => rec.dish.id)
        }
        .id('ingredients-recommend-list')
        .width('100%')
      }

      PrimaryButton({
        label: '重新推荐',
        iconVariant: 'search',
        onTap: () => { this.store.getRecommendations(); },
      })
        .width('100%')
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 100 })
  }

  @Builder
  EmptyState() {
    Column({ space: 10 }) {
      Stack() {
        SvgIcon({ variant: 'store', iconSize: 56, color: Theme.line, strokeWidth: 1.5 })
      }
      .width(80).height(80)
      Text('还没有食材')
        .fontSize(17).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
      Text('添加冰箱里的食材，立刻获得菜谱推荐')
        .fontSize(14).fontColor(Theme.textSecondary)
    }
    .id('ingredients-empty-state')
    .width('100%').padding({ top: 36, bottom: 36 }).alignItems(HorizontalAlign.Center)
  }

  @Builder
  MatchRing(match: number) {
    Stack() {
      Circle().width(46).height(46)
        .fill('rgba(0,0,0,0)')
        .stroke(Theme.line).strokeWidth(4)
      Progress({ value: match * 100, total: 100, type: ProgressType.Ring })
        .width(46).height(46)
        .color(Theme.avocado)
        .style({ strokeWidth: 4 } as ProgressStyleOptions)
      Text(`${Math.round(match * 100)}%`)
        .fontSize(11).fontWeight(FontWeight.Bold).fontColor(Theme.avocado)
    }
    .width(46).height(46)
  }
}

import { Theme } from '../common/Theme';
import { Chip, TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { Mood, MealTime, Cuisine } from '../common/Enums';
import { MOOD_LABELS, MEAL_TIME_LABELS, CUISINE_LABELS } from '../common/Enums';
import { FilterResult } from '../model/Models';

@Component
export struct FiltersPage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};

  private moodColor(m: Mood): string {
    if (m === Mood.Healthy) {
      return Theme.avocado;
    } else if (m === Mood.Treat) {
      return Theme.tomato;
    } else if (m === Mood.Budget) {
      return Theme.caramel;
    } else if (m === Mood.Lazy) {
      return Theme.mist;
    }
    return Theme.grape;
  }

  build() {
    Column({ space: 16 }) {
      TopBar({ title: '心情 / 时间筛选', onBack: () => this.onBack() })

      // Mood group
      Column({ space: 14 }) {
        Text('现在的心情')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([Mood.Healthy, Mood.Treat, Mood.Budget, Mood.Lazy, Mood.Adventurous], (m: Mood) => {
            Chip({
              label: MOOD_LABELS[m] ?? m,
              selected: this.store.filterSelections.mood === m,
              selectedColor: this.moodColor(m),
              onTap: () => { this.store.selectMood(m); },
            })
          }, (m: Mood) => m)
        }
        .id('filters-mood-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Time group
      Column({ space: 14 }) {
        Text('用餐时段')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([MealTime.Breakfast, MealTime.Lunch, MealTime.Dinner, MealTime.LateNight, MealTime.Tea], (t: MealTime) => {
            Chip({
              label: MEAL_TIME_LABELS[t] ?? t,
              selected: this.store.filterSelections.time === t,
              selectedColor: Theme.tomato,
              onTap: () => { this.store.selectTime(t); },
            })
          }, (t: MealTime) => t)
        }
        .id('filters-time-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Cuisine group
      Column({ space: 14 }) {
        Text('菜系偏好（可选）')
          .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach([Cuisine.Chinese, Cuisine.Western, Cuisine.Japanese, Cuisine.Korean, Cuisine.Light], (c: Cuisine) => {
            Chip({
              label: CUISINE_LABELS[c] ?? c,
              selected: this.store.filterSelections.cuisine === c,
              selectedColor: Theme.tomato,
              onTap: () => { this.store.selectCuisine(c); },
            })
          }, (c: Cuisine) => c)
        }
        .id('filters-cuisine-group')
        .width('100%')
      }
      .width('100%').padding(20).borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })

      // Result header
      Row() {
        Text('为你找到')
          .fontSize(18).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Blank()
        Text(`${this.store.filterResultCount()} 个结果`)
          .id('filters-result-count')
          .fontSize(13).fontColor(Theme.textSecondary)
      }
      .width('100%')

      // Result grid
      if (this.store.filterResults.length === 0) {
        Text('选择条件后点击“应用筛选”查看结果')
          .id('filters-no-results')
          .fontSize(14).fontColor(Theme.textTertiary)
          .width('100%').padding(24).textAlign(TextAlign.Center)
      } else {
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach(this.store.filterResults, (r: FilterResult) => {
            Column({ space: 4 }) {
              Text(r.dish.name)
                .fontSize(15).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
              Row({ space: 4 }) {
                ForEach(r.tags.slice(0, 2), (tag: string, idx: number) => {
                  Text(tag)
                    .fontSize(10).fontColor(Theme.textSecondary)
                    .padding({ left: 8, right: 8, top: 3, bottom: 3 })
                    .borderRadius(6).backgroundColor(Theme.tintNeutral)
                }, (tag: string) => tag)
              }
            }
            .id(`filter-result-${r.dish.id}`)
            .width('46%')
            .margin({ right: 12, bottom: 12 })
            .padding(16)
            .borderRadius(Theme.radiusCard)
            .backgroundColor(Theme.cardBgAlt)
            .shadow(Theme.cardShadow)
            .border({ width: 0.5, color: Theme.lineSoft })
            .alignItems(HorizontalAlign.Center)
          }, (r: FilterResult) => r.dish.id)
        }
        .id('filters-result-list')
        .width('100%')
      }

      // Bottom actions
      Row({ space: 12 }) {
        SecondaryButton({ label: '重置', onTap: () => { this.store.resetFilters(); } })
          .id('filters-reset-button')
          .width(110)
        PrimaryButton({
          label: '应用筛选',
          iconVariant: 'search',
          onTap: () => { this.store.applyFilters(); },
        })
          .id('filters-apply-button')
          .layoutWeight(1)
      }
      .width('100%')
      .margin({ top: 4 })
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }
}

import { promptAction } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { ShareService } from '../service/ShareService';
import { ShareTemplate } from '../common/Enums';

@Component
export struct SharePage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};

  private templateGrad(t: ShareTemplate): LinearGradient {
    if (t === ShareTemplate.Fresh) {
      return { angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tintAvocado, 0], [Theme.tintMist, 1]] } as LinearGradient;
    } else if (t === ShareTemplate.Classic) {
      return { angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.textPrimary, 0], ['#4A423A', 1]] } as LinearGradient;
    }
    return BrandGradient.hero;
  }

  private async onSave(): Promise<void> {
    const msg: string = await this.store.saveShareCardToAlbum();
    promptAction.showToast({ message: msg });
  }

  private async onShare(): Promise<void> {
    const msg: string = await this.store.shareCurrentCard();
    promptAction.showToast({ message: msg });
  }

  build() {
    Column({ space: 18 }) {
      TopBar({ title: '分享今日美食', onBack: () => this.onBack() })

      // Card preview
      Stack() {
        // decorative circles
        Circle().width(180).height(180).fill('rgba(255,216,92,0.35)')
          .position({ x: '62%', y: -60 })
        Circle().width(220).height(220).fill('rgba(232,85,69,0.12)')
          .position({ x: -60, y: '72%' })

        Column({ space: 14 }) {
          Blank().layoutWeight(1)
          Column({ space: 14 }) {
            Text(this.store.shareCard ? this.store.shareCard.date : this.store.todayLabel())
              .fontSize(13).fontColor(Theme.textSecondary)
            Text(this.store.shareCard ? this.store.shareCard.dish : '今天吃什么')
              .fontSize(34).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
            Text(this.store.shareCard && this.store.shareCard.caption.length > 0
              ? this.store.shareCard.caption : '写一句心情，记录这一餐的小确幸。')
              .fontSize(15).fontColor(Theme.textSecondary)
              .padding(16)
              .borderRadius(16)
              .backgroundColor('rgba(255,255,255,0.72)')
            Row({ space: 8 }) {
              if (this.store.shareCard) {
                Text(`#${this.store.shareCard.tag}`)
                  .fontSize(12).fontWeight(FontWeight.Medium).fontColor(Theme.tomato)
                  .padding({ left: 12, right: 12, top: 6, bottom: 6 })
                  .borderRadius(20).backgroundColor('#FFFFFF')
              }
            }
          }
          .alignItems(HorizontalAlign.Start)
          .width('100%')
          Blank().layoutWeight(1)
          Text('今天吃什么 · 记录每一餐')
            .fontSize(12).fontColor(Theme.textTertiary)
            .width('100%').textAlign(TextAlign.End)
        }
        .width('100%').height('100%').padding(28)
      }
      .id('share-card-preview')
      .width('100%')
      .height(460)
      .borderRadius(Theme.radiusHero)
      .linearGradient(this.templateGrad(this.store.shareTemplate))
      .shadow(Theme.heroShadow)
      .clip(true)

      // Caption input
      TextInput({ text: this.store.shareCaption, placeholder: '写一句心情...' })
        .id('share-caption-input')
        .width('100%')
        .fontSize(15)
        .fontColor(Theme.textPrimary)
        .backgroundColor(Theme.cardBgAlt)
        .borderRadius(Theme.radiusButton)
        .border({ width: 1.5, color: Theme.line })
        .padding({ left: 16, right: 16, top: 14, bottom: 14 })
        .onChange((v: string) => { this.store.setShareCaption(v); })

      // Template selector
      Row({ space: 10 }) {
        ForEach(ShareService.templates(), (t: ShareTemplate) => {
          Stack()
            .width(44).height(44).borderRadius(12)
            .border({ width: this.store.shareTemplate === t ? 2 : 0, color: Theme.tomato })
            .linearGradient(this.templateGrad(t))
            .onClick(() => { this.store.selectShareTemplate(t); })
        }, (t: ShareTemplate) => t)
      }
      .id('share-template-selector')
      .width('100%')
      .justifyContent(FlexAlign.Center)
      .margin({ bottom: 4 })

      // Actions
      Row({ space: 12 }) {
        SecondaryButton({ label: '保存到相册', iconVariant: 'card', onTap: () => { this.onSave(); } })
          .id('share-save-button')
          .layoutWeight(1)
        PrimaryButton({ label: '分享', iconVariant: 'card', onTap: () => { this.onShare(); } })
          .id('share-send-button')
          .layoutWeight(1)
      }
      .width('100%')
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }
}

import { promptAction } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { AppStore } from '../controller/AppStore';

@Component
export struct ProfilePage {
  @ObjectLink store: AppStore;

  private async onClearData(): Promise<void> {
    await this.store.clearAllData();
    promptAction.showToast({ message: '已清空所有本地数据' });
  }

  build() {
    Column({ space: 24 }) {
      Text('我的')
        .fontSize(28).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        .width('100%')
        .margin({ top: 8 })

      // Profile card
      Row({ space: 18 }) {
        Stack() {
          SvgIcon({ variant: 'profile', iconSize: 32, color: Theme.caramel, strokeWidth: 2 })
        }
        .width(64).height(64).borderRadius(32).backgroundColor('#FFFFFF')
        .shadow({ radius: 12, color: 'rgba(43,38,34,0.08)', offsetX: 0, offsetY: 4 } as ShadowOptions)
        Column({ space: 4 }) {
          Text(this.store.userName)
            .id('profile-username')
            .fontSize(20).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
          Text(`已连续打卡 ${this.store.streak()} 天 · 本月 ${this.store.monthlyCount()} 次`)
            .fontSize(13).fontColor(Theme.textSecondary)
        }
        .alignItems(HorizontalAlign.Start)
      }
      .width('100%').padding(26).borderRadius(Theme.radiusHero)
      .linearGradient(BrandGradient.hero).shadow(Theme.heroShadow)

      // Menu list
      Column({ space: 0 }) {
        this.MenuItem('profile-dish-library-button', Theme.caramel, Theme.tintCaramel, 'info', '菜品库', () => {
          promptAction.showToast({ message: '菜品库即将开放' });
        })
        this.MenuItem('profile-settings-button', Theme.mist, Theme.tintMist, 'settings', '设置', () => {
          promptAction.showToast({ message: '设置即将开放' });
        })
        this.MenuItem('profile-clear-data-button', Theme.tomato, Theme.tintTomato, 'trash', '清空所有数据', () => {
          this.onClearData();
        }, true)
        this.MenuItem('profile-version-label', Theme.textSecondary, Theme.tintNeutral, 'info', '关于 今天吃什么 v1.0.0', () => {
          promptAction.showToast({ message: '今天吃什么 v1.0.0' });
        })
      }
      .width('100%')
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt)
      .shadow(Theme.cardShadow)
      .border({ width: 0.5, color: Theme.lineSoft })
      .clip(true)
    }
    .width('100%')
    .height('100%')
    .padding({ left: 22, right: 22, bottom: 100 })
  }

  @Builder
  MenuItem(idValue: string, color: string, bg: string, icon: string, label: string, onTap: () => void, danger: boolean = false) {
    Row({ space: 14 }) {
      Stack() {
        SvgIcon({ variant: icon, iconSize: 22, color: color, strokeWidth: 2 })
      }
      .width(40).height(40).borderRadius(12).backgroundColor(bg)
      Text(label)
        .fontSize(16).fontWeight(FontWeight.Medium)
        .fontColor(danger ? Theme.tomato : Theme.textPrimary)
        .layoutWeight(1)
      SvgIcon({ variant: 'arrowRight', iconSize: 18, color: Theme.textTertiary, strokeWidth: 2 })
    }
    .id(idValue)
    .width('100%')
    .padding({ left: 20, right: 20, top: 18, bottom: 18 })
    .border({ width: { bottom: 0.5 }, color: { bottom: Theme.line } })
    .onClick(() => onTap())
  }
}

