import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { AppStore } from '../controller/AppStore';
import { MealSlot } from '../common/Enums';
import { MEAL_SLOT_LABELS, CHECK_IN_TAG_LABELS, MOOD_LABELS } from '../common/Enums';
import { MealStatus } from '../model/Models';
import { CheckIn } from '../model/Models';

@Component
export struct CheckInPage {
  @ObjectLink store: AppStore;

  private slotId(slot: MealSlot): string {
    if (slot === MealSlot.Breakfast) {
      return 'checkin-breakfast-button';
    } else if (slot === MealSlot.Lunch) {
      return 'checkin-lunch-button';
    } else if (slot === MealSlot.Dinner) {
      return 'checkin-dinner-button';
    }
    return 'checkin-snack-button';
  }

  private mealIconColor(slot: MealSlot): string {
    if (slot === MealSlot.Snack) {
      return Theme.grape;
    } else if (slot === MealSlot.Dinner) {
      return Theme.mist;
    }
    return Theme.caramel;
  }

  private mealIconBg(slot: MealSlot): string {
    if (slot === MealSlot.Snack) {
      return Theme.tintGrape;
    } else if (slot === MealSlot.Dinner) {
      return Theme.tintMist;
    }
    return Theme.tintCaramel;
  }

  build() {
    Column({ space: 16 }) {
      Text(this.store.todayLabel())
        .id('checkin-date-label')
        .fontSize(15).fontColor(Theme.textSecondary)
      Text('饮食打卡')
        .fontSize(28).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)

      // Stats
      Row({ space: 12 }) {
        Column({ space: 6 }) {
          Text(`${this.store.streak()}`)
            .id('checkin-streak-count')
            .fontSize(34).fontWeight(FontWeight.Bold).fontColor(Theme.avocado)
          Text('连续打卡天')
            .fontSize(13).fontColor(Theme.textSecondary)
        }
        .layoutWeight(1).padding(18).borderRadius(Theme.radiusCard)
        .linearGradient(BrandGradient.success).border({ width: 0.5, color: Theme.borderAvocadoSoft })
        .alignItems(HorizontalAlign.Center)

        Column({ space: 6 }) {
          Text(`${this.store.monthlyCount()}`)
            .id('checkin-monthly-count')
            .fontSize(34).fontWeight(FontWeight.Bold).fontColor(Theme.tomato)
          Text('本月打卡')
            .fontSize(13).fontColor(Theme.textSecondary)
        }
        .layoutWeight(1).padding(18).borderRadius(Theme.radiusCard)
        .backgroundColor(Theme.cardBgAlt).shadow(Theme.cardShadow).border({ width: 0.5, color: Theme.lineSoft })
        .alignItems(HorizontalAlign.Center)
      }
      .width('100%')

      Text('今日三餐')
        .fontSize(18).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(this.store.todayMeals(), (m: MealStatus) => {
          Column({ space: 10 }) {
            Row() {
              Stack() {
                SvgIcon({ variant: 'orders', iconSize: 22, color: this.mealIconColor(m.slot), strokeWidth: 2 })
              }
              .width(40).height(40).borderRadius(12).backgroundColor(this.mealIconBg(m.slot))
              Blank()
              if (m.completed) {
                Circle().width(20).height(20).fill(Theme.avocado)
              }
            }
            .width('100%')
            Text(m.label)
              .fontSize(16).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
            Text(m.completed ? m.dish : '尚未打卡')
              .fontSize(13)
              .fontColor(m.completed ? Theme.avocado : Theme.textSecondary)
          }
          .id(this.slotId(m.slot))
          .width('46%')
          .margin({ right: 12, bottom: 12 })
          .padding(16)
          .borderRadius(Theme.radiusCard)
          .backgroundColor(Theme.cardBgAlt)
          .shadow(Theme.cardShadow)
          .border({
            width: m.completed ? 4 : 0.5,
            color: m.completed ? Theme.avocado : Theme.lineSoft,
