// Index.ets — 今天吃什么 app shell.
//
// HEADLESS PHASE COMPILE-ANCHOR: this wires the AppStore into the fixed
// bottom-tab shell (BottomTabBar inside the Stack, tab-surface switching) so
// the project compiles and all headless logic is reachable. This is NOT the
// final visual layout — the visual integration phase replaces each
// TabSurface with the final HTML-derived page (Home/Wheel/Ingredients/Filters/
// CheckIn/Share/Profile), preserving the semantic IDs from ui-tree.json and
// this shell contract (BottomTabBar public API, TabId ownership, surface model).

import { common } from '@kit.AbilityKit';
import { Theme } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { BottomTabBar } from '../components/BottomTabBar';
import { AppStore } from '../controller/AppStore';

type AppSurface = 'home' | 'ingredients' | 'checkin' | 'profile';

@Entry
@Component
struct Index {
  @State surface: AppSurface = 'home';
  @State activeTab: TabId = 'tab-home';
  @State store: AppStore | null = null;

  aboutToAppear(): void {
    const ctx: common.Context = getContext(this) as common.Context;
    AppStore.create(ctx).then((s: AppStore) => {
      this.store = s;
    });
  }

  build() {
    Stack() {
      Stack({ alignContent: Alignment.Bottom }) {
        Column() {
          this.CurrentSurface()
        }
        .width('100%')
        .height('100%')
        .padding({
          bottom: Theme.bottomTabHeight + 24,
        })

        BottomTabBar({
          activeTab: this.activeTab,
          onTap: (tab: TabId): void => this.goToTab(tab),
        })
      }
      .width('100%')
      .height('100%')
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  CurrentSurface() {
    if (this.store === null) {
      Text('加载中…')
        .fontSize(16)
        .fontColor(Theme.textTertiary)
        .margin({ top: 80 })
    } else if (this.surface === 'home') {
      this.HomeSurface()
    } else if (this.surface === 'ingredients') {
      this.IngredientsSurface()
    } else if (this.surface === 'checkin') {
      this.CheckInSurface()
    } else {
      this.ProfileSurface()
    }
  }

  // Compile-anchor surfaces — minimal, non-final. Replaced by visual phase.
  @Builder
  HomeSurface() {
    Column({ space: 8 }) {
      Text(this.store!.greeting())
        .fontSize(20)
        .fontColor(Theme.textPrimary)
      Text(this.store!.todayLabel())
        .fontSize(14)
        .fontColor(Theme.textSecondary)
      Text(`连续打卡 ${this.store!.streak()} 天`)
        .fontSize(14)
        .fontColor(Theme.textSecondary)
    }
    .width('100%')
    .padding(Theme.pageHorizontalPadding)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  IngredientsSurface() {
    Column({ space: 8 }) {
      Text(`冰箱食材 ${this.store!.ingredients.length} 项`)
        .fontSize(18)
        .fontColor(Theme.textPrimary)
      Text(`推荐菜谱 ${this.store!.recommendations.length} 道`)
        .fontSize(14)
        .fontColor(Theme.textSecondary)
    }
    .width('100%')
    .padding(Theme.pageHorizontalPadding)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  CheckInSurface() {
    Column({ space: 8 }) {
      Text(`今日打卡 ${this.store!.todaySummary().completed}/${this.store!.todaySummary().total}`)
        .fontSize(18)
        .fontColor(Theme.textPrimary)
      Text(`连续 ${this.store!.streak()} 天 · 本月 ${this.store!.monthlyCount()} 次`)
        .fontSize(14)
        .fontColor(Theme.textSecondary)
    }
    .width('100%')
    .padding(Theme.pageHorizontalPadding)
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  ProfileSurface() {
    Column({ space: 8 }) {
      Text(this.store!.userName)
        .fontSize(20)
        .fontColor(Theme.textPrimary)
      Text(`菜品库 ${0} 道 · 版本 1.0.0`)
        .fontSize(14)
        .fontColor(Theme.textSecondary)
    }
    .width('100%')
    .padding(Theme.pageHorizontalPadding)
    .alignItems(HorizontalAlign.Start)
  }

  private goToTab(tab: TabId): void {
    this.activeTab = tab;
    if (tab === 'tab-home') {
      this.surface = 'home';
    } else if (tab === 'tab-ingredients') {
      this.surface = 'ingredients';
    } else if (tab === 'tab-checkin') {
      this.surface = 'checkin';
    } else {
      this.surface = 'profile';
    }
  }
}

