import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { TopBar, PrimaryButton, SecondaryButton } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { WheelState } from '../common/Enums';
import { WheelCandidate } from '../model/Models';

const WHEEL_SIZE: number = 280;
const WHEEL_R: number = 138;
const WHEEL_C: number = 140;

@Component
export struct WheelPage {
  @ObjectLink store: AppStore;
  onBack: () => void = () => {};
  onOpenShare: () => void = () => {};

  private sectorCmd(i: number): string {
    const n: number = this.store.wheelCandidates.length;
    const slice: number = 360 / n;
    const a0: number = (i * slice) * Math.PI / 180;
    const a1: number = ((i + 1) * slice) * Math.PI / 180;
    const x0: number = WHEEL_C + WHEEL_R * Math.sin(a0);
    const y0: number = WHEEL_C - WHEEL_R * Math.cos(a0);
    const x1: number = WHEEL_C + WHEEL_R * Math.sin(a1);
    const y1: number = WHEEL_C - WHEEL_R * Math.cos(a1);
    const large: number = slice > 180 ? 1 : 0;
    return `M${WHEEL_C} ${WHEEL_C} L${x0.toFixed(2)} ${y0.toFixed(2)} A${WHEEL_R} ${WHEEL_R} 0 ${large} 1 ${x1.toFixed(2)} ${y1.toFixed(2)} Z`;
  }

  private labelX(i: number): number {
    const n: number = this.store.wheelCandidates.length;
    const slice: number = 360 / n;
    const mid: number = (i * slice + slice / 2) * Math.PI / 180;
    return WHEEL_C + (WHEEL_R * 0.62) * Math.sin(mid);
  }

  private labelY(i: number): number {
    const n: number = this.store.wheelCandidates.length;
    const slice: number = 360 / n;
    const mid: number = (i * slice + slice / 2) * Math.PI / 180;
    return WHEEL_C - (WHEEL_R * 0.62) * Math.cos(mid);
  }

  private startSpin(): void {
    if (!this.store.startSpin()) {
      return;
    }
    const store: AppStore = this.store;
    animateTo({
      duration: store.spinDurationMs(),
      curve: Curve.EaseOut,
      onFinish: () => store.finishSpin(),
    }, () => {
      store.wheelRotation = store.spinTarget();
    });
  }

  build() {
    Column({ space: 18 }) {
      TopBar({ title: '转盘抽菜', onBack: () => this.onBack() })

      Column({ space: 28 }) {
        // Wheel
        Stack() {
          Stack() {
            Circle().width(WHEEL_SIZE).height(WHEEL_SIZE).fill('#FFFFFF')
            ForEach(this.store.wheelCandidates, (c: WheelCandidate, i: number) => {
              Path()
                .commands(this.sectorCmd(i))
                .fill(this.store.wheelSectorColor(i))
                .stroke('#FFFFFF')
                .strokeWidth(1)
            }, (c: WheelCandidate) => c.id)
            ForEach(this.store.wheelCandidates, (c: WheelCandidate, i: number) => {
              Text(c.name)
                .fontSize(13)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.textPrimary)
                .maxLines(1)
                .position({ x: this.labelX(i) - 30, y: this.labelY(i) - 8 })
                .width(60)
                .textAlign(TextAlign.Center)
            }, (c: WheelCandidate) => `t-${c.id}`)
            Circle().width(74).height(74).fill('#FFFFFF')
          }
          .width(WHEEL_SIZE)
          .height(WHEEL_SIZE)
          .rotate({ angle: this.store.wheelRotation })

          // Pointer (fixed, pointing down into the wheel top)
          Stack() {
            Path()
              .commands('M14 0 L28 26 L20 22 L14 30 L8 22 L0 26 Z')
              .fill(Theme.tomato)
          }
          .width(28)
          .height(30)
          .position({ x: (WHEEL_SIZE - 28) / 2, y: -10 })

          // Center start button
          Text(this.store.wheelState === WheelState.Spinning ? '…' : '开始')
            .id('wheel-start-button')
            .fontSize(15)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textOnBrand)
            .width(70)
            .height(70)
            .textAlign(TextAlign.Center)
            .borderRadius(35)
            .border({ width: 3, color: '#FFFFFF' })
            .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
            .shadow({ radius: 24, color: 'rgba(232,85,69,0.35)', offsetX: 0, offsetY: 8 } as ShadowOptions)
            .onClick(() => this.startSpin())
        }
        .width(WHEEL_SIZE)
        .height(WHEEL_SIZE + 20)
        .id('wheel-canvas')
        .alignContent(Alignment.Center)

        // Result
        Column({ space: 6 }) {
          Text('转盘结果')
            .fontSize(13)
            .fontColor(Theme.textSecondary)
          Text(this.store.wheelResult.length > 0 ? this.store.wheelResult : '点击开始')
            .id('wheel-result-label')
            .fontSize(26)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.tomato)
        }
        .padding({ left: 32, right: 32, top: 20, bottom: 20 })
        .borderRadius(Theme.radiusCard)
        .backgroundColor('#FFFFFF')
        .shadow(Theme.cardShadow)
        .border({ width: 0.5, color: Theme.lineSoft })

        // Actions
        Column({ space: 12 }) {
          if (this.store.wheelCandidates.length < 2) {
            Text('至少添加 2 个候选菜才能开始转盘')
              .fontSize(13)
              .fontColor(Theme.textTertiary)
          } else {
            PrimaryButton({
              label: this.store.wheelState === WheelState.Spinning ? '旋转中…' : '开始转盘',
              iconVariant: 'search',
              onTap: () => this.startSpin(),
            })
          }
          SecondaryButton({
            label: '再转一次',
            iconVariant: 'favorite',
            onTap: () => { this.store.spinAgain(); this.startSpin(); },
          })
          if (this.store.wheelResult.length > 0) {
            Text('为此结果打卡')
              .id('wheel-checkin-button')
              .fontSize(14)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textSecondary)
              .padding({ top: 8, bottom: 8 })
              .onClick(() => {
                this.store.openShareFromWheel();
                this.onOpenShare();
              })
          }
        }

        // Candidate list
        this.CandidateList()
      }
      .width('100%')
    }
    .width('100%')
    .padding({ left: 22, right: 22, bottom: 40 })
  }

  @Builder
  CandidateList() {
    Column({ space: 0 }) {
      Row() {
        Text('候选菜品')
          .fontSize(16)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Blank()
        Text('编辑')
          .id('wheel-edit-button')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
          .padding({ top: 6, bottom: 6, left: 10, right: 10 })
          .onClick(() => this.store.openWheelEditor())
      }
      .width('100%')
      .margin({ bottom: 10 })

      if (this.store.wheelCandidates.length === 0) {
        Text('还没有候选菜，点击右上角“编辑”添加')
          .id('wheel-empty-candidates')
          .fontSize(14)
          .fontColor(Theme.textTertiary)
          .padding({ top: 18, bottom: 18 })
      } else {
        ForEach(this.store.wheelCandidates, (c: WheelCandidate) => {
          Row() {
            Text(c.name)
              .id(`wheel-candidate-${c.id}`)
              .fontSize(15)
              .fontColor(Theme.textPrimary)
              .layoutWeight(1)
            Row({ space: 8 }) {
              Stack() {
                SvgIcon({ variant: 'info', iconSize: 16, color: Theme.textSecondary, strokeWidth: 2 })
              }
              .width(32).height(32).borderRadius(8).backgroundColor(Theme.tintNeutral)
              .onClick(() => this.store.openWheelEditor(c.id))
              Stack() {
                SvgIcon({ variant: 'trash', iconSize: 16, color: Theme.textSecondary, strokeWidth: 2 })
              }
              .id('wheel-editor-delete-button')
              .width(32).height(32).borderRadius(8).backgroundColor(Theme.tintNeutral)
              .onClick(() => this.store.deleteWheelCandidate(c.id))
            }
          }
          .width('100%')
          .padding({ top: 12, bottom: 12 })
          .border({ width: { bottom: 0.5 }, color: { bottom: Theme.line } })
        }, (c: WheelCandidate) => c.id)
      }

      Row({ space: 8 }) {
        SvgIcon({ variant: 'add', iconSize: 18, color: Theme.tomato, strokeWidth: 2 })
        Text('添加候选菜')
          .id('wheel-add-candidate-button')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.tomato)
      }
      .width('100%')
      .justifyContent(FlexAlign.Center)
      .padding({ top: 14, bottom: 6 })
      .border({ width: 1.5, color: Theme.borderTomatoSoft })
      .borderRadius(Theme.radiusButton)
      .backgroundColor('#FFFFFF')
      .margin({ top: 10 })
      .onClick(() => this.store.openWheelEditor())
    }
    .id('wheel-candidate-list')
    .width('100%')
    .padding(18)
    .borderRadius(Theme.radiusCard)
    .backgroundColor('#FFFFFF')
    .shadow(Theme.cardShadow)
    .border({ width: 0.5, color: Theme.lineSoft })
  }
}

import { promptAction } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { Chip } from '../common/Components';
import { AppStore } from '../controller/AppStore';
import { Mood, CheckInTag, MealSlot } from '../common/Enums';
import { MEAL_SLOT_LABELS } from '../common/Enums';

@Component
export struct CheckInFormSheet {
  @ObjectLink store: AppStore;

  private mealTitle(): string {
    return `打卡${MEAL_SLOT_LABELS[this.store.checkinActiveMeal] ?? ''}`;
  }

  private moodColor(m: Mood): string {
    if (m === Mood.Healthy) {
      return Theme.avocado;
    } else if (m === Mood.Treat) {
      return Theme.tomato;
    } else if (m === Mood.Budget) {
      return Theme.caramel;
    } else if (m === Mood.Lazy) {
      return Theme.mist;
    }
    return Theme.grape;
  }

  private tagColor(t: CheckInTag): string {
    if (t === CheckInTag.Takeout) {
      return Theme.mist;
    } else if (t === CheckInTag.Gathering) {
      return Theme.grape;
    }
    return Theme.caramel;
  }

  private async onSave(): Promise<void> {
    await this.store.saveCheckin();
    promptAction.showToast({ message: '打卡成功' });
  }

  build() {
    Column({ space: 0 }) {
      Row({ space: 14 }) {
        Stack() {
          SvgIcon({ variant: 'trash', iconSize: 22, color: Theme.textPrimary, strokeWidth: 2 })
        }
        .id('checkin-form-cancel-button')
        .width(44).height(44).borderRadius(22)
        .backgroundColor('rgba(255,255,255,0.82)')
        .border({ width: 0.5, color: Theme.lineSoft })
        .onClick(() => { this.store.cancelCheckin(); })
        Text(this.mealTitle())
          .id('checkin-form-meal-label')
          .fontSize(20).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        Blank()
      }
      .width('100%')
      .height(44)
      .margin({ bottom: 24 })

      Column({ space: 20 }) {
        Column({ space: 4 }) {
          Text('餐次').fontSize(13).fontColor(Theme.textSecondary)
          Text(MEAL_SLOT_LABELS[this.store.checkinActiveMeal] ?? '')
            .fontSize(24).fontWeight(FontWeight.Bold).fontColor(Theme.textPrimary)
        }
        .width('100%').alignItems(HorizontalAlign.Start)

        // Dish input
        Column({ space: 10 }) {
          Text('吃了什么').fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).width('100%')
          TextInput({ text: this.store.checkinDish, placeholder: '输入菜名，例如：番茄牛腩饭' })
            .id('checkin-form-dish-input')
            .width('100%').height(50).fontSize(15)
            .fontColor(Theme.textPrimary)
            .backgroundColor(Theme.cardBgAlt)
            .borderRadius(Theme.radiusButton)
            .border({ width: 1.5, color: Theme.line })
            .padding({ left: 18, right: 18 })
            .onChange((v: string) => { this.store.checkinDish = v; })
        }
        .width('100%')

        // Photo placeholder
        Column({ space: 8 }) {
          Text('照片记录').fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).width('100%')
          Row({ space: 8 }) {
            SvgIcon({ variant: 'card', iconSize: 32, color: Theme.textSecondary, strokeWidth: 2 })
            Text('添加照片').fontSize(15).fontColor(Theme.textSecondary)
          }
          .id('checkin-form-photo-button')
          .width('100%').height(140)
          .justifyContent(FlexAlign.Center)
          .borderRadius(Theme.radiusButton)
          .border({ width: 1.5, color: Theme.line, style: BorderStyle.Dashed })
          .backgroundColor(Theme.cardBgAlt)
          .onClick(() => { promptAction.showToast({ message: '照片选择即将开放' }); })
        }
        .width('100%')

        // Mood
        Column({ space: 10 }) {
          Text('此刻心情').fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).width('100%')
          Flex({ wrap: FlexWrap.Wrap }) {
            ForEach([Mood.Treat, Mood.Healthy, Mood.Lazy, Mood.Adventurous], (m: Mood) => {
              Chip({
                label: this.moodLabel(m),
                selected: this.store.checkinMood === m,
                selectedColor: this.moodColor(m),
                onTap: () => { this.store.checkinMood = m; },
              })
            }, (m: Mood) => m)
          }
          .id('checkin-form-mood-group')
          .width('100%')
        }
        .width('100%')

        // Tag
        Column({ space: 10 }) {
          Text('标签').fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.textPrimary).width('100%')
          Flex({ wrap: FlexWrap.Wrap }) {
            ForEach([CheckInTag.HomeCooked, CheckInTag.Takeout, CheckInTag.Gathering], (t: CheckInTag) => {
              Chip({
                label: this.tagLabel(t),
                selected: this.store.checkinTag === t,
                selectedColor: this.tagColor(t),
                onTap: () => { this.store.checkinTag = t; },
              })
            }, (t: CheckInTag) => t)
          }
          .id('checkin-form-tag-group')
          .width('100%')
        }
        .width('100%')

        // Actions
        Row({ space: 12 }) {
          Text('取消')
            .id('checkin-form-cancel-button')
            .fontSize(15).fontWeight(FontWeight.Medium).fontColor(Theme.tomato)
            .layoutWeight(1).textAlign(TextAlign.Center)
            .padding({ top: 14, bottom: 14 })
            .borderRadius(Theme.radiusButton)
            .backgroundColor('#FFFFFF')
            .border({ width: 1.5, color: Theme.borderTomatoSoft })
            .onClick(() => { this.store.cancelCheckin(); })
          Text('保存打卡')
            .id('checkin-form-save-button')
            .fontSize(15).fontWeight(FontWeight.Bold).fontColor(Theme.textOnBrand)
            .layoutWeight(1).textAlign(TextAlign.Center)
            .padding({ top: 14, bottom: 14 })
            .borderRadius(Theme.radiusButton)
            .linearGradient(BrandGradient.brand)
            .shadow(Theme.brandShadow)
            .onClick(() => { this.onSave(); })
        }
        .width('100%')
        .margin({ top: 8 })
      }
      .width('100%')
      .padding(24)
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBgAlt)
      .shadow(Theme.cardShadow)
      .border({ width: 0.5, color: Theme.lineSoft })
    }
    .width('100%')
    .padding({ left: 22, right: 22, top: 48 })
  }

  private moodLabel(m: Mood): string {
    if (m === Mood.Treat) {
      return '满足';
    } else if (m === Mood.Healthy) {
      return '活力';
    } else if (m === Mood.Lazy) {
      return '疲惫';
    }
    return '治愈';
  }

  private tagLabel(t: CheckInTag): string {
    if (t === CheckInTag.Takeout) {
      return '外卖';
    } else if (t === CheckInTag.Gathering) {
      return '聚餐';
    }
    return '自制';
  }
}

