import { common } from '@kit.AbilityKit';
import { Theme } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { BottomTabBar } from '../components/BottomTabBar';
import { WheelEditorSheet } from '../components/WheelEditorSheet';
import { CheckInFormSheet } from '../components/CheckInFormSheet';
import { SvgIcon } from '../common/SvgIcon';
import { AppStore } from '../controller/AppStore';
import { HomePage } from '../pages/HomePage';
import { WheelPage } from '../pages/WheelPage';
import { IngredientsPage } from '../pages/IngredientsPage';
import { FiltersPage } from '../pages/FiltersPage';
import { CheckInPage } from '../pages/CheckInPage';
import { SharePage } from '../pages/SharePage';
import { ProfilePage } from '../pages/ProfilePage';

type AppSurface = 'home' | 'ingredients' | 'checkin' | 'profile' | 'wheel' | 'filters' | 'share';

@Entry
@Component
struct Index {
  @State surface: AppSurface = 'home';
  @State activeTab: TabId = 'tab-home';
  @State store: AppStore | null = null;

  aboutToAppear(): void {
    const ctx: common.Context = getContext(this) as common.Context;
    AppStore.create(ctx).then((s: AppStore) => {
      this.store = s;
    });
  }

  private isTabSurface(): boolean {
    return this.surface === 'home' || this.surface === 'ingredients' ||
      this.surface === 'checkin' || this.surface === 'profile';
  }

  private goToTab(tab: TabId): void {
    this.activeTab = tab;
    if (tab === 'tab-home') {
      this.surface = 'home';
    } else if (tab === 'tab-ingredients') {
      this.surface = 'ingredients';
    } else if (tab === 'tab-checkin') {
      this.surface = 'checkin';
    } else {
      this.surface = 'profile';
    }
  }

  private goBackToTab(): void {
    this.goToTab(this.activeTab);
  }

  build() {
    Stack() {
      Column() {
        Scroll() {
          Column() {
            this.CurrentSurface()
          }
          .width('100%')
          .constraintSize({ maxWidth: Theme.contentMaxWidth })
        }
        .width('100%')
        .layoutWeight(1)
        .scrollBar(BarState.Off)
        .align(Alignment.Top)

        if (this.isTabSurface() && this.store !== null) {
          BottomTabBar({
            activeTab: this.activeTab,
            onTap: (tab: TabId): void => this.goToTab(tab),
          })
        }
      }
      .width('100%')
      .height('100%')

      // Check-in floating share button overlay
      if (this.surface === 'checkin' && this.store !== null) {
        Stack() {
          SvgIcon({ variant: 'card', iconSize: 24, color: Theme.textOnBrand, strokeWidth: 2 })
        }
        .id('checkin-share-button')
        .width(56)
        .height(56)
        .borderRadius(28)
        .linearGradient({ angle: 135, direction: GradientDirection.RightTop, colors: [[Theme.tomato, 0], [Theme.caramel, 1]] } as LinearGradient)
        .shadow({ radius: 20, color: 'rgba(232,85,69,0.32)', offsetX: 0, offsetY: 6 } as ShadowOptions)
        .position({ x: '62%', y: '76%' })
        .onClick(() => {
          this.store.openShareFromCheckin();
          this.surface = 'share';
        })
      }

      // Wheel editor overlay
      if (this.store !== null && this.store.editorOpen) {
        this.Scrim()
        Column() {
          WheelEditorSheet({ store: this.store })
        }
        .width('100%')
        .constraintSize({ maxWidth: Theme.contentMaxWidth })
      }

      // Check-in form overlay
      if (this.store !== null && this.store.checkinFormOpen) {
        this.Scrim()
        Column() {
          CheckInFormSheet({ store: this.store })
        }
        .width('100%')
        .constraintSize({ maxWidth: Theme.contentMaxWidth })
      }
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  Scrim() {
    Column()
      .width('100%')
      .height('100%')
      .backgroundColor(Theme.overlayScrim)
      .position({ x: 0, y: 0 })
  }

  @Builder
  CurrentSurface() {
    if (this.store === null) {
      Column() {
        Text('加载中…')
          .fontSize(16)
          .fontColor(Theme.textTertiary)
      }
      .width('100%')
      .height('100%')
      .justifyContent(FlexAlign.Center)
    } else if (this.surface === 'home') {
      HomePage({
        store: this.store,
        onOpenWheel: (): void => { this.surface = 'wheel'; },
        onGoIngredients: (): void => this.goToTab('tab-ingredients'),
        onOpenFilters: (): void => { this.surface = 'filters'; },
        onGoCheckin: (): void => this.goToTab('tab-checkin'),
      })
    } else if (this.surface === 'wheel') {
      WheelPage({
        store: this.store,
        onBack: (): void => this.goBackToTab(),
        onOpenShare: (): void => { this.surface = 'share'; },
      })
    } else if (this.surface === 'ingredients') {
      IngredientsPage({ store: this.store })
    } else if (this.surface === 'filters') {
      FiltersPage({ store: this.store, onBack: (): void => this.goBackToTab() })
    } else if (this.surface === 'checkin') {
      CheckInPage({ store: this.store })
    } else if (this.surface === 'share') {
      SharePage({ store: this.store, onBack: (): void => this.goBackToTab() })
    } else {
      ProfilePage({ store: this.store })
    }
  }
}
